import React, { useState, useEffect, useMemo } from 'react';
import type { FormData, ModelName, LinkedFile, ExamDatabaseRecord } from '../types';
import { UploadIcon } from './icons/UploadIcon';
import { TrashIcon } from './icons/TrashIcon';
import { AVAILABLE_MODELS } from '../constants';
import { SearchIcon } from './icons/SearchIcon';
import { LoadingSpinnerIcon } from './icons/LoadingSpinnerIcon';
import { PlusCircleIcon } from './icons/PlusCircleIcon';

interface InputFormProps {
  formData: FormData;
  onFormChange: (newFormData: Partial<FormData>) => void;
  onGenerate: () => void;
  onSearchCriteria: (selectedRecord?: ExamDatabaseRecord) => void;
  isLoading: boolean;
  isSearching: boolean;
}

const modelLabels: Record<ModelName, string> = {
  'gemini-2.5-flash': 'Gemini 2.5 Flash',
  'gemini-2.5-pro': 'Gemini 2.5 Pro',
  'gemini-3-flash-preview': 'Gemini 3.0 Flash',
  'gemini-3-pro-preview': 'Gemini 3.0 Pro',
};

// Helper to extract text inside parentheses
const extractTypeName = (fullType: string) => {
  if (!fullType) return '기본 유형';
  const match = fullType.match(/\(([^)]+)\)/);
  return match ? match[1] : fullType;
};

const FileInputField: React.FC<{
  label: string;
  files: LinkedFile[];
  onFilesChange: (files: LinkedFile[]) => void;
  name: string;
  description: string;
}> = ({ label, files, onFilesChange, name, description }) => {
  const handleUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).map((f: File) => ({ name: f.name, file: f }));
      onFilesChange([...files, ...newFiles]);
    }
  };

  return (
    <div className="space-y-2">
      <label className="block text-sm font-medium text-stone-400">{label}</label>
      <p className="text-xs text-stone-500">{description}</p>
      <div className="flex flex-wrap gap-2">
        {files.map((f, i) => (
          <div key={i} className="flex items-center bg-stone-800 px-3 py-1.5 rounded-lg border border-stone-700 text-xs">
            {f.url ? (
              <a href={f.url} target="_blank" rel="noreferrer" className="text-sky-400 hover:underline mr-2 truncate max-w-[120px]">{f.name}</a>
            ) : (
              <span className="text-stone-300 mr-2 truncate max-w-[120px]">{f.name}</span>
            )}
            <button onClick={() => onFilesChange(files.filter((_, idx) => idx !== i))} className="text-stone-500 hover:text-red-400">
              <TrashIcon className="w-3 h-3" />
            </button>
          </div>
        ))}
        <label className="cursor-pointer bg-stone-900 border border-dashed border-stone-700 px-3 py-1.5 rounded-lg text-xs text-stone-500 hover:border-sky-500 hover:text-sky-400 flex items-center">
          <UploadIcon className="w-3 h-3 mr-1" /> 추가
          <input type="file" className="sr-only" onChange={handleUpload} multiple />
        </label>
      </div>
    </div>
  );
};

export const InputForm: React.FC<InputFormProps> = ({ formData, onFormChange, onGenerate, onSearchCriteria, isLoading, isSearching }) => {
  const [isAdminOpen, setIsAdminOpen] = useState(false);

  const availableRecords = useMemo(() => {
    if (!formData.university && !formData.examYear) return [];
    const dbStr = localStorage.getItem('exam_database');
    if (!dbStr) return [];
    const db: ExamDatabaseRecord[] = JSON.parse(dbStr);

    return db.filter(r => {
      const univMatch = !formData.university || (r.university.toLowerCase().includes(formData.university.toLowerCase()) || formData.university.toLowerCase().includes(r.university.toLowerCase()));
      const yearMatch = !formData.examYear || (r.year.toString().includes(formData.examYear) || formData.examYear.includes(r.year.toString()));
      return univMatch && yearMatch;
    });
  }, [formData.university, formData.examYear]);

  const handleCsvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const text = ev.target?.result as string;
        const rows = text.split(/\r?\n/).filter(r => r.trim()).slice(1);
        const db: ExamDatabaseRecord[] = rows.map(row => {
          // Robust split that handles potential quoted values
          const parts = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || row.split(',').map(s => s.trim());
          const cleanedParts = parts.map(p => p.replace(/^"|"$/g, '').trim());
          const [univ, year, pType, pUrl, sUrl] = cleanedParts;
          return { university: univ, year, problemType: pType, problemUrl: pUrl, solutionUrl: sUrl };
        });
        localStorage.setItem('exam_database', JSON.stringify(db));
        alert(`${db.length}개의 시험 정보가 등록되었습니다.`);
      };
      reader.readAsText(file);
    }
  };

  const handleTypeSelect = (record: ExamDatabaseRecord) => {
    // Determine the type name to set (if user likes to see the extracted one or full one)
    // Here we set the full one as it's more descriptive for the database match
    onFormChange({ 
      university: record.university,
      examYear: record.year,
      problemType: record.problemType
    });
    // Triggers App.tsx's handleSearchCriteria(record) which populates URLs and AI search
    onSearchCriteria(record);
  };

  return (
    <div className="bg-stone-900/50 border border-stone-800 p-8 rounded-xl shadow-2xl backdrop-blur-lg space-y-6">
      <div className="flex justify-between items-center">
        <div className="flex items-center space-x-3">
          <h2 className="text-xl font-bold text-stone-100">시험 정보 및 자료</h2>
          <div className="flex items-center bg-stone-800 px-2 py-1 rounded border border-stone-700">
            <span className="text-[10px] text-stone-500 uppercase font-bold mr-2">Model</span>
            <select 
              value={formData.model}
              onChange={(e) => onFormChange({ model: e.target.value as ModelName })}
              className="bg-transparent text-xs text-sky-400 outline-none cursor-pointer"
            >
              {AVAILABLE_MODELS.map(m => (
                <option key={m} value={m} className="bg-stone-900">{modelLabels[m]}</option>
              ))}
            </select>
          </div>
        </div>
        <button onClick={() => setIsAdminOpen(!isAdminOpen)} className="text-xs text-stone-500 hover:text-stone-300 underline">
          {isAdminOpen ? '관리자 닫기' : '관리자 모드'}
        </button>
      </div>

      {isAdminOpen && (
        <div className="p-4 bg-stone-800/40 border border-stone-700 rounded-lg space-y-3">
          <p className="text-xs text-stone-400 font-bold italic">CSV Format: University, Year, Type, ProblemUrl, SolutionUrl</p>
          <input type="file" accept=".csv" onChange={handleCsvUpload} className="text-xs text-stone-300 block w-full file:mr-4 file:py-1 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-sky-900 file:text-sky-300 hover:file:bg-sky-800" />
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-stone-400 mb-2">대학교</label>
          <input
            type="text"
            value={formData.university}
            onChange={(e) => onFormChange({ university: e.target.value })}
            placeholder="예: 서울대학교"
            className="w-full px-4 py-2 bg-stone-900/50 border border-stone-700 rounded-lg text-stone-200 text-sm focus:border-sky-500 outline-none transition"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-stone-400 mb-2">출제 년도</label>
          <input
            type="text"
            value={formData.examYear}
            onChange={(e) => onFormChange({ examYear: e.target.value })}
            placeholder="예: 2024"
            className="w-full px-4 py-2 bg-stone-900/50 border border-stone-700 rounded-lg text-stone-200 text-sm focus:border-sky-500 outline-none transition"
          />
        </div>
      </div>

      {availableRecords.length > 0 && (
        <div className="p-4 bg-stone-800/20 border border-stone-700/50 rounded-lg space-y-3 animate-in fade-in slide-in-from-top-2 duration-300">
          <label className="block text-[10px] font-bold text-stone-500 uppercase tracking-wider">검색된 문제 유형 (선택 시 자동 완성)</label>
          <div className="flex flex-wrap gap-2">
            {availableRecords.map((r, i) => {
              const extractedType = extractTypeName(r.problemType);
              const isSelected = formData.problemType === r.problemType;
              return (
                <button
                  key={i}
                  onClick={() => handleTypeSelect(r)}
                  className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
                    isSelected 
                    ? 'bg-sky-600 border-sky-500 text-white shadow-lg shadow-sky-900/40 ring-2 ring-sky-500/20' 
                    : 'bg-stone-800 border-stone-700 text-stone-400 hover:border-sky-500/50 hover:text-stone-200'
                  }`}
                  title={r.problemType}
                >
                  {extractedType}
                </button>
              );
            })}
          </div>
        </div>
      )}

      <div className="space-y-2">
        <label className="block text-sm font-medium text-stone-400">문제 유형 (직접 입력 가능)</label>
        <input
          type="text"
          value={formData.problemType}
          onChange={(e) => onFormChange({ problemType: e.target.value })}
          placeholder="예: 자연계열, 의예과 등"
          className="w-full px-4 py-2 bg-stone-900/50 border border-stone-700 rounded-lg text-stone-200 text-sm focus:border-sky-500 outline-none transition"
        />
      </div>

      <button
        onClick={() => onSearchCriteria()}
        disabled={!formData.university || !formData.examYear || isSearching || isLoading}
        className="w-full flex items-center justify-center py-3 bg-stone-800 hover:bg-stone-700 text-stone-200 rounded-lg text-sm font-bold border border-stone-700 transition-all disabled:opacity-50"
      >
        {isSearching ? <LoadingSpinnerIcon className="animate-spin w-4 h-4 mr-2" /> : <SearchIcon className="w-4 h-4 mr-2" />}
        전체 정보 수동 검색 및 기준 생성
      </button>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-4 border-t border-stone-800">
        <FileInputField
          label="1. 문제 자료"
          name="problemMaterials"
          files={formData.problemMaterials}
          onFilesChange={(fs) => onFormChange({ problemMaterials: fs })}
          description="학생 배포용 문제 파일"
        />
        <FileInputField
          label="2. 채점 기준/해설"
          name="scoringMaterials"
          files={formData.scoringMaterials}
          onFilesChange={(fs) => onFormChange({ scoringMaterials: fs })}
          description="AI 채점용 정답지"
        />
      </div>

      <div className="space-y-2">
        <label className="block text-sm font-medium text-stone-400">AI 생성 채점 기준 (텍스트)</label>
        <div className="relative">
          <textarea
            value={formData.scoringCriteria}
            onChange={(e) => onFormChange({ scoringCriteria: e.target.value })}
            placeholder="검색 결과 또는 생성된 채점 기준이 여기에 표시됩니다."
            className="w-full h-32 px-4 py-3 bg-stone-900/50 border border-stone-700 rounded-lg text-xs text-stone-300 focus:border-sky-500 outline-none transition leading-relaxed"
          />
          {isSearching && (
            <div className="absolute inset-0 bg-stone-900/40 backdrop-blur-[1px] flex items-center justify-center rounded-lg">
              <LoadingSpinnerIcon className="animate-spin w-6 h-6 text-sky-500" />
            </div>
          )}
        </div>
      </div>

      <div className="border-t border-stone-800 pt-6">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-lg font-bold text-stone-200">학생 목록</h3>
          <button onClick={() => onFormChange({ students: [...formData.students, { id: crypto.randomUUID(), name: '', email: '', solutionFiles: [], reportTemplate: '' }] })} className="text-sky-400 hover:text-sky-300 flex items-center text-sm">
            <PlusCircleIcon className="w-4 h-4 mr-1" /> 추가
          </button>
        </div>

        <div className="space-y-3 max-h-64 overflow-y-auto pr-2">
          {formData.students.length === 0 ? (
            <p className="text-center py-4 text-stone-500 text-xs italic">학생을 추가하고 답안지를 업로드하세요.</p>
          ) : (
            formData.students.map((s, idx) => (
              <div key={s.id} className="p-4 bg-stone-800/30 border border-stone-700 rounded-lg relative">
                 <button onClick={() => onFormChange({ students: formData.students.filter(std => std.id !== s.id) })} className="absolute top-2 right-2 text-stone-500 hover:text-red-400 transition">
                  <TrashIcon className="w-4 h-4" />
                </button>
                <div className="grid grid-cols-2 gap-2 mb-3">
                  <input value={s.name} onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, name: e.target.value} : item) })} placeholder="학생 이름" className="bg-stone-900 px-3 py-1.5 rounded border border-stone-700 text-xs text-stone-200 outline-none" />
                  <input value={s.email} onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, email: e.target.value} : item) })} placeholder="이메일" className="bg-stone-900 px-3 py-1.5 rounded border border-stone-700 text-xs text-stone-200 outline-none" />
                </div>
                <label className="block text-[10px] text-stone-500 mb-1">학생 답안지 업로드</label>
                <input type="file" multiple onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, solutionFiles: Array.from(e.target.files || [])} : item) })} className="text-[10px] text-stone-400" />
              </div>
            ))
          )}
        </div>
      </div>

      <button
        onClick={onGenerate}
        disabled={isLoading || formData.students.length === 0}
        className="w-full py-4 bg-gradient-to-r from-sky-600 to-indigo-600 hover:from-sky-500 hover:to-indigo-500 text-white rounded-xl font-bold text-lg shadow-lg transform transition active:scale-95 disabled:opacity-50"
      >
        {isLoading ? '분석 및 보고서 생성 중...' : `보고서 일괄 생성 시작 (${formData.students.length}명)`}
      </button>
    </div>
  );
};

import { saveToGoogleSheets } from './services/googleSheetsService';
import React, { useState, useCallback } from 'react';
import { InputForm } from './components/InputForm';
import { ReportDisplay } from './components/ReportDisplay';
import { ReportPlaceholder } from './components/ReportPlaceholder';
import { StudentProgressView } from './components/StudentProgressView';
import { gradeSolutionAndGenerateFeedback, formatReportToHtml, searchScoringCriteria, extractReportData } from './services/geminiService';
import type { FormData, ReportData, ExamDatabaseRecord, LinkedFile } from './types';
import { initialFormData } from './constants';
import { CheckCircleIcon } from './components/icons/CheckCircleIcon';
import { ExclamationCircleIcon } from './components/icons/ExclamationCircleIcon';
import { LoadingSpinnerIcon } from './components/icons/LoadingSpinnerIcon';

interface ReportResult {
  status: 'loading' | 'done' | 'error';
  data?: ReportData;
  error?: string;
  studentName: string;
  studentId: string;
  progressMessage?: string;
}

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormData>(initialFormData);
  const [results, setResults] = useState<ReportResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSearching, setIsSearching] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [selectedStudentForProgress, setSelectedStudentForProgress] = useState<{ id: string, name: string } | null>(null);

  const handleSearchCriteria = useCallback(async (selectedRecord?: ExamDatabaseRecord) => {
    setIsSearching(true);
    const { university, examYear, problemType, model } = formData;

    let problemFiles: LinkedFile[] = [];
    let scoringFiles: LinkedFile[] = [];

    // Use specific record if provided, otherwise search in local DB
    let targetUniv = university;
    let targetYear = examYear;
    let targetType = problemType;

    if (selectedRecord) {
      targetUniv = selectedRecord.university;
      targetYear = selectedRecord.year;
      targetType = selectedRecord.problemType;

      if (selectedRecord.problemUrl) problemFiles.push({ name: `${selectedRecord.university}_${selectedRecord.year}_문제`, url: selectedRecord.problemUrl });
      if (selectedRecord.solutionUrl) scoringFiles.push({ name: `${selectedRecord.university}_${selectedRecord.year}_해설`, url: selectedRecord.solutionUrl });
    } else {
      // Try to find in localStorage if no record passed
      const dbStr = localStorage.getItem('exam_database');
      if (dbStr) {
        const db: ExamDatabaseRecord[] = JSON.parse(dbStr);
        const match = db.find(r => 
          (university.toLowerCase().includes(r.university.toLowerCase()) || r.university.toLowerCase().includes(university.toLowerCase())) && 
          (examYear.toString().includes(r.year.toString()) || r.year.toString().includes(examYear.toString())) &&
          (!problemType || r.problemType.toLowerCase().includes(problemType.toLowerCase()) || problemType.toLowerCase().includes(r.problemType.toLowerCase()))
        );

        if (match) {
          if (match.problemUrl) problemFiles.push({ name: `${match.university}_${match.year}_문제`, url: match.problemUrl });
          if (match.solutionUrl) scoringFiles.push({ name: `${match.university}_${match.year}_해설`, url: match.solutionUrl });
        }
      }
    }

    try {
      // Search for criteria text via AI/Web search
      const criteria = await searchScoringCriteria(targetUniv, targetYear, targetType, model);

      setFormData(prev => ({ 
        ...prev, 
        scoringCriteria: criteria,
        problemMaterials: problemFiles.length > 0 ? problemFiles : prev.problemMaterials,
        scoringMaterials: scoringFiles.length > 0 ? scoringFiles : prev.scoringMaterials,
        university: targetUniv,
        examYear: targetYear,
        problemType: targetType
      }));

    } catch (e) {
      console.error(e);
      alert("검색 중 오류가 발생했습니다.");
    } finally {
      setIsSearching(false);
    }
  }, [formData]);

  const handleGenerateReport = useCallback(async () => {
    setIsLoading(true);
    const studentsToProcess = formData.students;
    const examInfo = `${formData.university} ${formData.examYear} ${formData.problemType}`.trim();

    setProgress({ current: 0, total: studentsToProcess.length });
    setResults(studentsToProcess.map(s => ({ studentId: s.id, studentName: s.name, status: 'loading', progressMessage: '대기 중...' })));

    for (let i = 0; i < studentsToProcess.length; i++) {
      const student = studentsToProcess[i];
      setProgress(prev => ({ ...prev, current: i + 1 }));

      try {
        const generationDate = new Date().toLocaleString('ko-KR');
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, progressMessage: 'AI가 분석 및 채점 중...' } : r));

        const rawReport = await gradeSolutionAndGenerateFeedback(
          { 
            university: formData.university, 
            examYear: formData.examYear, 
            problemType: formData.problemType,
            scoringCriteria: formData.scoringCriteria, 
            model: formData.model,
            problemMaterials: formData.problemMaterials,
            scoringMaterials: formData.scoringMaterials
          },
          { name: student.name, solutionFiles: student.solutionFiles, reportTemplate: student.reportTemplate }
        );

        const htmlReport = await formatReportToHtml(
          rawReport,
          { university: formData.university, examYear: formData.examYear, problemType: formData.problemType, model: formData.model },
          student.name,
          generationDate
        );

        try {
          const extracted = await extractReportData(rawReport, formData.model);
          const storageKey = `student_history_${student.id}`;
          const existing = localStorage.getItem(storageKey);
          const history = existing ? JSON.parse(existing) : { studentId: student.id, studentName: student.name, records: [] };
          history.records.push({
            id: crypto.randomUUID(),
            date: generationDate,
            examInfo: examInfo,
            problemType: formData.problemType,
            ...extracted
          });
          localStorage.setItem(storageKey, JSON.stringify(history));
          saveToGoogleSheets({
            studentId: student.id, studentName: student.name, date: generationDate, examInfo: examInfo,
            ...extracted
          });
        } catch (ee) {
          console.error("데이터 저장 실패:", ee);
        }

        const reportData: ReportData = {
          htmlContent: htmlReport,
          studentEmail: student.email,
          studentName: student.name,
          examInfo: examInfo,
          generationDate
        };

        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'done', data: reportData, progressMessage: undefined } : r));
      } catch (e) {
        const message = e instanceof Error ? e.message : '오류 발생';
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'error', error: message, progressMessage: undefined } : r));
      }
    }
    setIsLoading(false);
  }, [formData]);

  const handleFormChange = (newFormData: Partial<FormData>) => setFormData(prev => ({ ...prev, ...newFormData }));

  return (
    <div className="min-h-screen w-full font-sans flex flex-col">
      <header className="sticky top-0 z-10 bg-stone-900/50 backdrop-blur-md border-b border-stone-800">
        <div className="container mx-auto px-6 py-4">
          <h1 className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-sky-400 to-fuchsia-500">
            수리논술 AI 채점 센터
          </h1>
        </div>
      </header>

      <main className="container mx-auto p-6 grid grid-cols-1 lg:grid-cols-2 gap-8 flex-grow items-start">
        <div className="lg:sticky top-24">
          <InputForm
            formData={formData}
            onFormChange={handleFormChange}
            onGenerate={handleGenerateReport}
            onSearchCriteria={handleSearchCriteria}
            isLoading={isLoading}
            isSearching={isSearching}
          />
        </div>
        <div>
          {results.length === 0 ? <ReportPlaceholder /> : (
            <div className="bg-stone-900/50 border border-stone-800 rounded-xl shadow-2xl overflow-hidden backdrop-blur-lg">
              <div className="p-4 border-b border-stone-800 bg-stone-900/40">
                <h2 className="font-bold text-stone-100">채점 결과 리스트 ({progress.current}/{progress.total})</h2>
              </div>
              <div className="p-2 space-y-2">
                {results.map(r => (
                  <details key={r.studentId} className="bg-stone-800/40 rounded-lg overflow-hidden" open={r.status !== 'loading'}>
                    <summary className="p-4 flex justify-between items-center cursor-pointer hover:bg-stone-700/30 transition">
                      <span className="font-bold text-stone-200">{r.studentName}</span>
                      <div className="flex items-center gap-3">
                         {r.status === 'done' && <button onClick={(e) => { e.stopPropagation(); setSelectedStudentForProgress({id: r.studentId, name: r.studentName}); }} className="text-[10px] bg-sky-900/50 text-sky-400 px-2 py-1 rounded border border-sky-800 hover:bg-sky-800 transition">발전분석</button>}
                         {r.status === 'loading' ? <span className="text-xs text-sky-400 animate-pulse">{r.progressMessage}</span> : 
                          r.status === 'done' ? <CheckCircleIcon className="w-5 h-5 text-green-500" /> : <ExclamationCircleIcon className="w-5 h-5 text-red-500" />}
                      </div>
                    </summary>
                    <div className="border-t border-stone-800">
                      {r.status === 'done' && r.data && <ReportDisplay reportData={r.data} />}
                      {r.status === 'error' && <div className="p-4 text-red-400 text-sm">{r.error}</div>}
                    </div>
                  </details>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      {selectedStudentForProgress && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center p-4">
           <div className="bg-stone-900 border border-stone-800 w-full max-w-2xl max-h-[90vh] overflow-y-auto rounded-2xl shadow-2xl">
              <div className="sticky top-0 bg-stone-900 p-4 border-b border-stone-800 flex justify-between items-center z-10">
                 <h2 className="font-bold text-stone-100">학습 데이터 분석</h2>
                 <button onClick={() => setSelectedStudentForProgress(null)} className="text-stone-500 hover:text-stone-100 text-2xl transition-colors">×</button>
              </div>
              <div className="p-6">
                 <StudentProgressView studentId={selectedStudentForProgress.id} studentName={selectedStudentForProgress.name} />
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

