interface InputFormProps {
  formData: FormData;
  onFormChange: (newFormData: Partial<FormData>) => void;
  onGenerate: () => void;
  onSearchCriteria: (selectedRecord?: ExamDatabaseRecord) => void;
  isLoading: boolean;
  isSearching: boolean;
}

const modelLabels: Record<ModelName, string> = {
  'gemini-2.5-flash': 'Gemini 2.5 Flash',
  'gemini-2.5-pro': 'Gemini 2.5 Pro',
  'gemini-3-flash-preview': 'Gemini 3.0 Flash',
  'gemini-3-pro-preview': 'Gemini 3.0 Pro',
};

// 괄호 속의 내용을 추출하여 버튼 이름으로 사용
const extractButtonLabel = (fullType: string) => {
  if (!fullType) return '일반';
  const match = fullType.match(/\(([^)]+)\)/);
  if (match && match[1]) return match[1];
  return fullType;
};

const MaterialBox: React.FC<{
  label: string;
  files: LinkedFile[];
  onFilesChange: (files: LinkedFile[]) => void;
  description: string;
}> = ({ label, files, onFilesChange, description }) => {
