        </div>
      </header>

      <main className="container mx-auto p-6 grid grid-cols-1 lg:grid-cols-2 gap-10 flex-grow items-start max-w-7xl">
        <div className="lg:sticky top-28">
          <InputForm
            formData={formData}
            onFormChange={handleFormChange}
            onGenerate={handleGenerateReport}
            onSearchCriteria={handleSearchCriteria}
            isLoading={isLoading}
            isSearching={isSearching}
          />
        </div>
        <div className="space-y-6">
          {results.length === 0 ? <ReportPlaceholder /> : (
            <div className="bg-stone-900/40 border border-stone-800/60 rounded-2xl shadow-2xl overflow-hidden backdrop-blur-xl">
              <div className="p-5 border-b border-stone-800/80 bg-stone-900/60 flex justify-between items-center">
                <h2 className="font-bold text-stone-100 flex items-center">
                   <div className={`w-2 h-2 rounded-full mr-3 ${isLoading ? 'bg-sky-500 animate-pulse' : 'bg-green-500'}`}></div>
                   채점 프로세스 리스트
                </h2>
                <span className="text-xs font-mono text-stone-500 bg-stone-950 px-2 py-0.5 rounded border border-stone-800">
                  {progress.current} / {progress.total}
                </span>
              </div>
              <div className="p-3 space-y-3">
                {results.map(r => (
                  <details key={r.studentId} className="bg-stone-900 border border-stone-800/40 rounded-xl overflow-hidden group transition-all" open={r.status !== 'loading'}>
                    <summary className="p-4 flex justify-between items-center cursor-pointer hover:bg-stone-800/40 transition-colors list-none">
                      <div className="flex items-center space-x-3">
                        <div className="w-8 h-8 rounded-lg bg-stone-800 flex items-center justify-center font-bold text-stone-400 group-open:bg-sky-900/30 group-open:text-sky-400 transition-colors">
                          {r.studentName.slice(0, 1)}
                        </div>
                        <span className="font-bold text-stone-200">{r.studentName}</span>
                      </div>
                      <div className="flex items-center gap-3">
                         {r.status === 'done' && <button onClick={(e) => { e.stopPropagation(); setSelectedStudentForProgress({id: r.studentId, name: r.studentName}); }} className="text-[10px] bg-stone-800 text-stone-400 px-3 py-1 rounded-lg border border-stone-700 hover:bg-sky-900/30 hover:text-sky-400 hover:border-sky-800 transition">데이터 시각화</button>}
                         {r.status === 'loading' ? <span className="text-[10px] text-sky-400 font-bold uppercase tracking-tight animate-pulse">{r.progressMessage}</span> : 
                          r.status === 'done' ? <CheckCircleIcon className="w-5 h-5 text-green-500" /> : <ExclamationCircleIcon className="w-5 h-5 text-red-500" />}
                      </div>
                    </summary>
                    <div className="border-t border-stone-800/50 bg-stone-950/30">
                      {r.status === 'done' && r.data && <ReportDisplay reportData={r.data} />}
                      {r.status === 'error' && <div className="p-8 text-center"><p className="text-red-400 text-sm font-bold mb-2">분석 중 오류 발생</p><p className="text-stone-500 text-xs">{r.error}</p></div>}
                    </div>
                  </details>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      {selectedStudentForProgress && (
        <div className="fixed inset-0 bg-stone-950/90 backdrop-blur-md z-50 flex items-center justify-center p-4 animate-in fade-in duration-300">
           <div className="bg-stone-900 border border-stone-800 w-full max-w-4xl max-h-[90vh] overflow-hidden rounded-3xl shadow-3xl flex flex-col">
              <div className="p-6 border-b border-stone-800 flex justify-between items-center bg-stone-900/50">
                 <div>
                    <h2 className="text-xl font-bold text-stone-100">{selectedStudentForProgress.name} 학생 분석 리포트</h2>
                    <p className="text-xs text-stone-500">누적 데이터를 바탕으로 한 성취도 및 역량 분석</p>
                 </div>
                 <button onClick={() => setSelectedStudentForProgress(null)} className="w-10 h-10 rounded-full bg-stone-800 text-stone-400 hover:bg-stone-700 hover:text-white flex items-center justify-center transition-colors">
                   <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                 </button>
              </div>
              <div className="p-6 overflow-y-auto bg-stone-950/50 scrollbar-thin">
                 <StudentProgressView studentId={selectedStudentForProgress.id} studentName={selectedStudentForProgress.name} />
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import type { FormData, ModelName, LinkedFile, ExamDatabaseRecord } from '../types';
import { UploadIcon } from './icons/UploadIcon';
import { TrashIcon } from './icons/TrashIcon';
import { AVAILABLE_MODELS } from '../constants';
import { SearchIcon } from './icons/SearchIcon';
import { LoadingSpinnerIcon } from './icons/LoadingSpinnerIcon';
import { PlusCircleIcon } from './icons/PlusCircleIcon';
import { LinkIcon } from './icons/LinkIcon';

interface InputFormProps {
  formData: FormData;
  onFormChange: (newFormData: Partial<FormData>) => void;
  onGenerate: () => void;
  onSearchCriteria: (selectedRecord?: ExamDatabaseRecord) => void;
  isLoading: boolean;
  isSearching: boolean;
}

const modelLabels: Record<ModelName, string> = {
  'gemini-2.5-flash': 'Gemini 2.5 Flash',
  'gemini-2.5-pro': 'Gemini 2.5 Pro',
  'gemini-3-flash-preview': 'Gemini 3.0 Flash',
  'gemini-3-pro-preview': 'Gemini 3.0 Pro',
};

// 문제유형에서 연도 등을 제외하고 뒤의 텍스트(예: 논술문제(자연계열))만 추출
const extractDisplayLabel = (fullType: string) => {
  if (!fullType) return '일반 유형';
  // 숫자로 시작하는 연도(예: 2025) 뒤의 텍스트를 찾음
  const match = fullType.match(/\d{4}\s*(.*)/);
  if (match && match[1]) return match[1].trim();
  return fullType;
};

const MaterialBox: React.FC<{
  label: string;
  files: LinkedFile[];
  onFilesChange: (files: LinkedFile[]) => void;
  description: string;
  icon: React.ReactNode;
}> = ({ label, files, onFilesChange, description, icon }) => {
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).map((f: File) => ({ name: f.name, file: f }));
      onFilesChange([...files, ...newFiles]);
    }
  };

  return (
    <div className="bg-stone-900/80 border border-stone-800 rounded-2xl p-5 flex flex-col h-full group hover:border-stone-700 transition-all">
      <div className="flex justify-between items-start mb-4">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-stone-800 rounded-lg text-stone-400 group-hover:text-sky-400 transition-colors">
            {icon}
          </div>
          <div>
            <h4 className="text-sm font-bold text-stone-100">{label}</h4>
            <p className="text-[10px] text-stone-500">{description}</p>
          </div>
        </div>
        <label className="cursor-pointer bg-sky-500/10 hover:bg-sky-500/20 text-sky-400 border border-sky-500/20 px-3 py-1.5 rounded-lg text-[10px] font-bold transition-all flex items-center">
          <UploadIcon className="w-3 h-3 mr-1.5" /> PDF/파일
          <input type="file" className="sr-only" onChange={handleFileUpload} multiple accept=".pdf,.png,.jpg,.jpeg" />
        </label>
      </div>

      <div className="flex-grow space-y-2 overflow-y-auto max-h-40 min-h-[100px] scrollbar-thin pr-2">
        {files.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center border border-dashed border-stone-800 rounded-xl py-6 opacity-50">
            <span className="text-[10px] text-stone-600 italic">등록된 자료가 없습니다</span>
          </div>
        ) : (
          files.map((f, i) => (
            <div key={i} className="flex items-center justify-between bg-stone-800/40 border border-stone-700/50 px-3 py-2.5 rounded-xl group/item hover:bg-stone-800 transition-colors">
              <div className="flex items-center min-w-0 flex-1 mr-2">
                {f.url ? <LinkIcon className="w-3.5 h-3.5 text-sky-500 mr-2.5 shrink-0" /> : <div className="w-2 h-2 rounded-full bg-stone-600 mr-2.5 shrink-0" />}
                {f.url ? (
                  <a href={f.url} target="_blank" rel="noreferrer" className="text-xs text-stone-300 hover:text-sky-400 truncate underline decoration-stone-700 underline-offset-4">{f.name}</a>
                ) : (
                  <span className="text-xs text-stone-400 truncate">{f.name}</span>
                )}
              </div>
              <button onClick={() => onFilesChange(files.filter((_, idx) => idx !== i))} className="text-stone-600 hover:text-red-400 transition-colors p-1">
                <TrashIcon className="w-3.5 h-3.5" />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export const InputForm: React.FC<InputFormProps> = ({ formData, onFormChange, onGenerate, onSearchCriteria, isLoading, isSearching }) => {
  const [isAdminOpen, setIsAdminOpen] = useState(false);

  const availableRecords = useMemo(() => {
    if (!formData.university && !formData.examYear) return [];
    const dbStr = localStorage.getItem('exam_database');
    if (!dbStr) return [];
    const db: ExamDatabaseRecord[] = JSON.parse(dbStr);

    return db.filter(r => {
      const univMatch = !formData.university || r.university.toLowerCase().includes(formData.university.toLowerCase());
      const yearMatch = !formData.examYear || r.year.toString().includes(formData.examYear);
      return univMatch && yearMatch;
    });
  }, [formData.university, formData.examYear]);

  const handleCsvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const text = ev.target?.result as string;
        const rows = text.split(/\r?\n/).filter(r => r.trim()).slice(1);
        const db: ExamDatabaseRecord[] = rows.map(row => {
          const parts = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || row.split(',').map(s => s.trim());
          const cleanedParts = parts.map(p => p.replace(/^"|"$/g, '').trim());
          const [univ, year, pType, pUrl, sUrl] = cleanedParts;
          return { university: univ, year: year || '', problemType: pType || '', problemUrl: pUrl || '', solutionUrl: sUrl || '' };
        });
        localStorage.setItem('exam_database', JSON.stringify(db));
        alert(`${db.length}개의 데이터베이스 정보가 등록되었습니다.`);
      };
      reader.readAsText(file);
    }
  };

  const handleTypeSelect = (record: ExamDatabaseRecord) => {
    onFormChange({ 
      university: record.university,
      examYear: record.year,
      problemType: record.problemType
    });
    onSearchCriteria(record);
