  isSearching: boolean;
}

const modelLabels: Record<ModelName, string> = {
  'gemini-2.5-flash': 'Gemini 2.5 Flash',
  'gemini-2.5-pro': 'Gemini 2.5 Pro',
  'gemini-3-flash-preview': 'Gemini 3.0 Flash',
  'gemini-3-pro-preview': 'Gemini 3.0 Pro',
};

// 대학교 이름과 출제년도를 제외한 나머지 텍스트만 추출하는 헬퍼 함수
const extractCleanLabel = (fullType: string, univ: string, year: string) => {
  if (!fullType) return '기타 유형';
  let label = fullType;
  if (univ) {
    const univRegex = new RegExp(univ.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
    label = label.replace(univRegex, '');
  }
  if (year) {
    const yearRegex = new RegExp(year, 'g');
    label = label.replace(yearRegex, '');
  }
  return label.trim() || fullType;
};

