};

export const InputForm: React.FC<InputFormProps> = ({ formData, onFormChange, onGenerate, onSearchCriteria, isLoading, isSearching }) => {
  const [isAdminOpen, setIsAdminOpen] = useState(false);

  const availableRecords = useMemo(() => {
    if (!formData.university && !formData.examYear) return [];
    const dbStr = localStorage.getItem('exam_database');
    if (!dbStr) return [];
    const db: ExamDatabaseRecord[] = JSON.parse(dbStr);

    return db.filter(r => {
      const univMatch = formData.university && r.university.toLowerCase().includes(formData.university.toLowerCase());
      const yearMatch = formData.examYear && r.year.toString().includes(formData.examYear);
      return univMatch && yearMatch;
    });
  }, [formData.university, formData.examYear]);

  const handleCsvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const text = ev.target?.result as string;
        const rows = text.split(/\r?\n/).filter(r => r.trim()).slice(1);
        const db: ExamDatabaseRecord[] = rows.map(row => {
          const parts = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || row.split(',').map(s => s.trim());
          const cleanedParts = parts.map(p => p.replace(/^"|"$/g, '').trim());
          const [univ, year, pType, pUrl, sUrl] = cleanedParts;
          return { university: univ || '', year: year || '', problemType: pType || '', problemUrl: pUrl || '', solutionUrl: sUrl || '' };
        });
        localStorage.setItem('exam_database', JSON.stringify(db));
        alert(`${db.length}개의 데이터베이스 정보가 로드되었습니다.`);
      };
      reader.readAsText(file);
    }
  };

  const handleTypeSelect = (record: ExamDatabaseRecord) => {
    onFormChange({ 
      problemType: record.problemType
    });
    // App.tsx의 handleSearchCriteria가 호출되어 URL 매핑과 웹 검색을 수행함
    onSearchCriteria(record);
  };

  return (
    <div className="bg-stone-950/40 border border-stone-800/60 p-8 rounded-[2rem] shadow-3xl backdrop-blur-2xl space-y-8">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-black text-stone-100 flex items-center tracking-tight">
          <span className="w-1.5 h-6 bg-gradient-to-b from-sky-400 to-indigo-600 rounded-full mr-4"></span>
          시험 설정
        </h2>
        <div className="flex items-center space-x-3">
          <select 
            value={formData.model}
            onChange={(e) => onFormChange({ model: e.target.value as ModelName })}
            className="bg-stone-900 text-[11px] font-bold text-sky-400 border border-stone-800 px-4 py-2 rounded-xl outline-none cursor-pointer hover:border-sky-500/30 transition shadow-inner"
          >
            {AVAILABLE_MODELS.map(m => (
              <option key={m} value={m} className="bg-stone-950">{modelLabels[m]}</option>
            ))}
          </select>
          <button onClick={() => setIsAdminOpen(!isAdminOpen)} className="p-2 bg-stone-900 border border-stone-800 rounded-xl text-stone-500 hover:text-stone-200 transition-all shadow-inner">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>
        </div>
      </div>

      {isAdminOpen && (
        <div className="p-5 bg-sky-950/10 border border-sky-500/10 rounded-2xl space-y-4 animate-in fade-in zoom-in duration-300">
          <p className="text-[10px] text-sky-400 font-black uppercase tracking-[0.2em]">CSV 데이터베이스 로드 (Univ, Year, Type, ProbUrl, SolUrl)</p>
          <input type="file" accept=".csv" onChange={handleCsvUpload} className="text-[11px] text-stone-500 file:mr-4 file:py-2 file:px-6 file:rounded-xl file:border-0 file:text-[11px] file:font-black file:bg-sky-500 file:text-white hover:file:bg-sky-400 transition-all cursor-pointer" />
        </div>
      )}

      <div className="grid grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">대학교</label>
          <input
            type="text"
            value={formData.university}
            onChange={(e) => onFormChange({ university: e.target.value })}
            placeholder="대학교 입력"
            className="w-full px-5 py-3.5 bg-stone-900 border border-stone-800 rounded-2xl text-stone-100 text-sm focus:border-sky-500/50 focus:ring-4 focus:ring-sky-500/5 outline-none transition shadow-inner"
          />
        </div>
        <div className="space-y-2">
          <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">출제 년도</label>
          <input
            type="text"
            value={formData.examYear}
            onChange={(e) => onFormChange({ examYear: e.target.value })}
            placeholder="2025"
            className="w-full px-5 py-3.5 bg-stone-900 border border-stone-800 rounded-2xl text-stone-100 text-sm focus:border-sky-500/50 focus:ring-4 focus:ring-sky-500/5 outline-none transition shadow-inner"
          />
        </div>
      </div>

      {availableRecords.length > 0 && (
        <div className="space-y-4 pt-2 animate-in fade-in slide-in-from-top-2 duration-500">
          <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">문제 유형 (대학교/년도 기반 검색됨)</label>
          <div className="flex flex-col space-y-2">
            {availableRecords.map((r, i) => (
              <button
                key={i}
                onClick={() => handleTypeSelect(r)}
                className={`w-full text-left px-5 py-3.5 rounded-2xl text-xs font-bold transition-all border-2 flex justify-between items-center group ${
                  formData.problemType === r.problemType 
                  ? 'bg-sky-500/10 border-sky-500 text-sky-400 shadow-xl shadow-sky-500/5' 
                  : 'bg-stone-900 border-stone-800 text-stone-400 hover:border-stone-700 hover:bg-stone-800/50'
                }`}
              >
                <span>{extractCleanLabel(r.problemType, formData.university, formData.examYear)}</span>
                <div className={`w-2 h-2 rounded-full transition-all ${formData.problemType === r.problemType ? 'bg-sky-400 scale-125' : 'bg-stone-700 group-hover:bg-stone-500'}`}></div>
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <MaterialBox
          label="문제 자료"
          files={formData.problemMaterials}
          onFilesChange={(fs) => onFormChange({ problemMaterials: fs })}
          description="선택 시 데이터베이스 URL이 자동 삽입됩니다"
          icon={<svg xmlns="http://www.w3.org/2000/svg" className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>}
        />
        <MaterialBox
          label="채점 기준 / 해설"
          files={formData.scoringMaterials}
          onFilesChange={(fs) => onFormChange({ scoringMaterials: fs })}
          description="선택 시 데이터베이스 URL이 자동 삽입됩니다"
          icon={<svg xmlns="http://www.w3.org/2000/svg" className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" /></svg>}
        />
      </div>

      <div className="space-y-3">
        <div className="flex justify-between items-center px-1">
          <label className="text-[10px] font-black text-stone-500 uppercase tracking-[0.2em]">웹 검색된 채점 기준 요약</label>
          {isSearching && (
            <div className="flex items-center space-x-2 text-sky-400">
              <LoadingSpinnerIcon className="w-3.5 h-3.5 animate-spin" />
              <span className="text-[10px] font-black uppercase">Web Searching...</span>
            </div>
          )}
        </div>
        <textarea
          value={formData.scoringCriteria}
          onChange={(e) => onFormChange({ scoringCriteria: e.target.value })}
          placeholder="문제 유형을 선택하면 웹 검색을 통해 채점 기준이 자동 정리됩니다."
          className="w-full h-44 px-6 py-5 bg-stone-900 border border-stone-800 rounded-[1.5rem] text-xs text-stone-300 focus:border-sky-500/50 outline-none transition-all leading-relaxed resize-none scrollbar-thin shadow-inner"
        />
      </div>

      <div className="border-t border-stone-800/50 pt-6">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-sm font-black text-stone-200 uppercase tracking-widest">학생 채점 목록</h3>
          <button onClick={() => onFormChange({ students: [...formData.students, { id: crypto.randomUUID(), name: '', email: '', solutionFiles: [], reportTemplate: '' }] })} className="bg-stone-800 hover:bg-stone-700 border border-stone-700 px-4 py-2 rounded-xl text-[11px] font-black text-stone-300 transition-all flex items-center shadow-sm">
            <PlusCircleIcon className="w-4 h-4 mr-2 text-sky-500" /> 학생 추가
          </button>
        </div>

        <div className="space-y-4 max-h-64 overflow-y-auto pr-2 scrollbar-thin">
          {formData.students.length === 0 ? (
            <div className="text-center py-10 border-2 border-dashed border-stone-800/50 rounded-3xl opacity-30">
              <p className="text-[11px] text-stone-600 font-bold uppercase tracking-widest">채점할 학생을 추가하세요</p>
            </div>
          ) : (
            formData.students.map((s) => (
              <div key={s.id} className="p-5 bg-stone-900 border border-stone-800 rounded-2xl relative shadow-sm">
                <button onClick={() => onFormChange({ students: formData.students.filter(std => std.id !== s.id) })} className="absolute top-4 right-4 text-stone-700 hover:text-red-500 transition-colors p-1">
                  <TrashIcon className="w-4 h-4" />
                </button>
                <div className="grid grid-cols-2 gap-4 mb-4">
                  <input value={s.name} onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, name: e.target.value} : item) })} placeholder="학생 이름" className="bg-stone-950 px-4 py-2 rounded-xl border border-stone-800 text-xs text-stone-100 outline-none focus:border-sky-500/30 transition shadow-inner" />
                  <input value={s.email} onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, email: e.target.value} : item) })} placeholder="이메일" className="bg-stone-950 px-4 py-2 rounded-xl border border-stone-800 text-xs text-stone-100 outline-none focus:border-sky-500/30 transition shadow-inner" />
                </div>
                <label className="flex items-center justify-center w-full px-4 py-3 border-2 border-dashed border-stone-800 rounded-xl cursor-pointer hover:border-sky-500/40 hover:bg-sky-500/5 transition-all">
                  <span className="text-[10px] font-black text-stone-600 uppercase tracking-tighter">
                    {s.solutionFiles.length > 0 ? `📄 ${s.solutionFiles.length}개의 답안지 로드됨` : '답안지 (이미지/PDF) 업로드'}
                  </span>
                  <input type="file" multiple onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, solutionFiles: Array.from(e.target.files || [])} : item) })} className="sr-only" />
                </label>
              </div>
            ))
          )}
        </div>
      </div>

      <button
        onClick={onGenerate}
        disabled={isLoading || formData.students.length === 0 || !formData.scoringCriteria}
        className="w-full py-5 bg-gradient-to-r from-sky-600 to-indigo-600 hover:from-sky-500 hover:to-indigo-500 text-white rounded-[1.5rem] font-black text-lg shadow-2xl shadow-sky-900/40 transform transition active:scale-[0.98] disabled:opacity-30 disabled:grayscale flex items-center justify-center"
      >
        {isLoading ? (
          <div className="flex items-center">
            <LoadingSpinnerIcon className="animate-spin w-6 h-6 mr-3" />
            AI 보고서 생성 중...
          </div>
        ) : (
          <div className="flex items-center">
            <span className="mr-2">채점 및 보고서 생성</span>
            <span className="px-2 py-0.5 bg-white/20 rounded-lg text-xs font-black">{formData.students.length}명</span>
          </div>
        )}
      </button>
    </div>
  );
};

import { saveToGoogleSheets } from './services/googleSheetsService';
import React, { useState, useCallback } from 'react';
import { InputForm } from './components/InputForm';
import { ReportDisplay } from './components/ReportDisplay';
import { ReportPlaceholder } from './components/ReportPlaceholder';
import { StudentProgressView } from './components/StudentProgressView';
import { gradeSolutionAndGenerateFeedback, formatReportToHtml, searchScoringCriteria, extractReportData } from './services/geminiService';
import type { FormData, ReportData, ExamDatabaseRecord, LinkedFile } from './types';
import { initialFormData } from './constants';
import { CheckCircleIcon } from './components/icons/CheckCircleIcon';
import { ExclamationCircleIcon } from './components/icons/ExclamationCircleIcon';
import { LoadingSpinnerIcon } from './components/icons/LoadingSpinnerIcon';

interface ReportResult {
  status: 'loading' | 'done' | 'error';
  data?: ReportData;
  error?: string;
  studentName: string;
  studentId: string;
  progressMessage?: string;
}

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormData>(initialFormData);
  const [results, setResults] = useState<ReportResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSearching, setIsSearching] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [selectedStudentForProgress, setSelectedStudentForProgress] = useState<{ id: string, name: string } | null>(null);

  // 대학교/년도를 제외한 짧은 라벨 추출 (파일명 생성용)
  const extractShortLabel = (fullType: string, univ: string, year: string) => {
    if (!fullType) return '유형';
    let label = fullType;
    if (univ) label = label.replace(new RegExp(univ, 'gi'), '');
    if (year) label = label.replace(new RegExp(year, 'g'), '');
    return label.trim();
  };

  const handleSearchCriteria = useCallback(async (selectedRecord?: ExamDatabaseRecord) => {
    setIsSearching(true);

    // 타겟 정보 결정
    const targetUniv = selectedRecord?.university || formData.university;
    const targetYear = selectedRecord?.year || formData.examYear;
    const targetType = selectedRecord?.problemType || formData.problemType;
    const model = formData.model;

    try {
      // 1. 자료 자동 매핑 (LinkedFile 구조)
      const problemMaterials: LinkedFile[] = [];
      const scoringMaterials: LinkedFile[] = [];

      if (selectedRecord) {
        const shortType = extractShortLabel(selectedRecord.problemType, targetUniv, targetYear);
        if (selectedRecord.problemUrl) {
          problemMaterials.push({ 
            name: `${shortType} 문제 (URL)`, 
            url: selectedRecord.problemUrl 
          });
        }
        if (selectedRecord.solutionUrl) {
          scoringMaterials.push({ 
            name: `${shortType} 해설 (URL)`, 
            url: selectedRecord.solutionUrl 
          });
        }
      }

      // 2. AI 웹 검색을 통한 채점 기준 정리
      const criteria = await searchScoringCriteria(targetUniv, targetYear, targetType, model);

      setFormData(prev => ({ 
        ...prev, 
        university: targetUniv,
        examYear: targetYear,
        problemType: targetType,
        scoringCriteria: criteria,
        // 선택된 레코드의 URL이 있다면 기존 URL 파일들을 대체하고 로컬 업로드 파일은 유지
        problemMaterials: problemMaterials.length > 0 ? [...problemMaterials, ...prev.problemMaterials.filter(p => !p.url)] : prev.problemMaterials,
        scoringMaterials: scoringMaterials.length > 0 ? [...scoringMaterials, ...prev.scoringMaterials.filter(s => !s.url)] : prev.scoringMaterials
      }));

    } catch (e) {
      console.error(e);
      alert("데이터베이스 연동 및 웹 검색 중 오류가 발생했습니다.");
    } finally {
      setIsSearching(false);
    }
  }, [formData]);

  const handleGenerateReport = useCallback(async () => {
    setIsLoading(true);
    const studentsToProcess = formData.students;
    const examInfo = `${formData.university} ${formData.examYear} ${formData.problemType}`.trim();

    setProgress({ current: 0, total: studentsToProcess.length });
    setResults(studentsToProcess.map(s => ({ studentId: s.id, studentName: s.name, status: 'loading', progressMessage: '대기 중...' })));

    for (let i = 0; i < studentsToProcess.length; i++) {
      const student = studentsToProcess[i];
      setProgress(prev => ({ ...prev, current: i + 1 }));

      try {
        const generationDate = new Date().toLocaleString('ko-KR');
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, progressMessage: 'AI 채점 분석 중...' } : r));

        const rawReport = await gradeSolutionAndGenerateFeedback(
          { 
            university: formData.university, 
            examYear: formData.examYear, 
            problemType: formData.problemType,
            scoringCriteria: formData.scoringCriteria, 
            model: formData.model,
            problemMaterials: formData.problemMaterials,
            scoringMaterials: formData.scoringMaterials
          },
          { name: student.name, solutionFiles: student.solutionFiles, reportTemplate: student.reportTemplate }
        );

        const htmlReport = await formatReportToHtml(
          rawReport,
          { university: formData.university, examYear: formData.examYear, problemType: formData.problemType, model: formData.model },
          student.name,
          generationDate
        );

        try {
          const extracted = await extractReportData(rawReport, formData.model);
          const storageKey = `student_history_${student.id}`;
          const existing = localStorage.getItem(storageKey);
          const history = existing ? JSON.parse(existing) : { studentId: student.id, studentName: student.name, records: [] };
          history.records.push({
            id: crypto.randomUUID(),
            date: generationDate,
            examInfo: examInfo,
            problemType: formData.problemType,
            ...extracted
          });
          localStorage.setItem(storageKey, JSON.stringify(history));
          saveToGoogleSheets({
            studentId: student.id, studentName: student.name, date: generationDate, examInfo: examInfo,
            ...extracted
          });
        } catch (ee) {
          console.error("데이터 저장 실패:", ee);
        }

        const reportData: ReportData = {
          htmlContent: htmlReport,
          studentEmail: student.email,
          studentName: student.name,
          examInfo: examInfo,
          generationDate
        };

        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'done', data: reportData, progressMessage: undefined } : r));
      } catch (e) {
        const message = e instanceof Error ? e.message : '오류 발생';
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'error', error: message, progressMessage: undefined } : r));
      }
    }
    setIsLoading(false);
  }, [formData]);

  const handleFormChange = (newFormData: Partial<FormData>) => setFormData(prev => ({ ...prev, ...newFormData }));

  return (
    <div className="min-h-screen w-full font-sans flex flex-col bg-[#0c0a09] text-stone-300">
      <header className="sticky top-0 z-10 bg-[#0c0a09]/80 backdrop-blur-2xl border-b border-stone-800/40">
        <div className="container mx-auto px-8 py-6 flex justify-between items-center max-w-[1400px]">
          <div className="flex items-center space-x-4">
            <div className="w-10 h-10 bg-gradient-to-br from-sky-400 to-indigo-600 rounded-2xl flex items-center justify-center shadow-lg shadow-sky-900/20">
              <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
            </div>
            <h1 className="text-2xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-sky-400 via-indigo-400 to-fuchsia-400">
              수리논술 AI 채점 센터
            </h1>
          </div>
          <div className="flex items-center space-x-4">
             <div className="text-[10px] font-black text-stone-500 uppercase tracking-widest bg-stone-900/50 border border-stone-800 px-4 py-1.5 rounded-full shadow-inner">
               Beta v2.5 • Powered by Gemini
             </div>
          </div>
        </div>
      </header>

      <main className="container mx-auto p-8 grid grid-cols-1 lg:grid-cols-2 gap-12 flex-grow items-start max-w-[1400px]">
        <div className="lg:sticky top-32">
          <InputForm
            formData={formData}
            onFormChange={handleFormChange}
            onGenerate={handleGenerateReport}
            onSearchCriteria={handleSearchCriteria}
            isLoading={isLoading}
            isSearching={isSearching}
          />
        </div>
        <div className="space-y-8">
          {results.length === 0 ? <ReportPlaceholder /> : (
            <div className="bg-stone-900/30 border border-stone-800/50 rounded-[2.5rem] shadow-3xl overflow-hidden backdrop-blur-2xl">
              <div className="p-8 border-b border-stone-800/50 bg-stone-900/40 flex justify-between items-center">
                <div className="flex items-center">
                   <div className={`w-3 h-3 rounded-full mr-4 ${isLoading ? 'bg-sky-500 animate-pulse' : 'bg-green-500'} shadow-[0_0_15px_rgba(14,165,233,0.5)]`}></div>
                   <h2 className="font-black text-stone-100 uppercase tracking-wider">채점 결과 분석</h2>
                </div>
                <div className="flex items-center space-x-3">
                  <span className="text-xs font-black text-stone-500 bg-stone-950/50 px-3 py-1 rounded-full border border-stone-800 shadow-inner">
                    {progress.current} / {progress.total} Completed
                  </span>
                </div>
              </div>
              <div className="p-6 space-y-4">
                {results.map(r => (
                  <details key={r.studentId} className="bg-stone-900/50 border border-stone-800/40 rounded-3xl overflow-hidden group transition-all" open={r.status !== 'loading'}>
                    <summary className="p-5 flex justify-between items-center cursor-pointer hover:bg-stone-800/30 transition-all list-none select-none">
                      <div className="flex items-center space-x-4">
                        <div className="w-12 h-12 rounded-2xl bg-stone-800/80 border border-stone-700/50 flex items-center justify-center font-black text-stone-400 group-open:bg-sky-500/10 group-open:text-sky-400 group-open:border-sky-500/20 transition-all text-lg shadow-inner">
                          {r.studentName.slice(0, 1)}
                        </div>
                        <div>
                          <p className="font-black text-stone-100 text-base">{r.studentName}</p>
                          <p className="text-[10px] text-stone-500 uppercase font-bold tracking-tight">Student ID: {r.studentId.slice(0, 8)}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-4">
                         {r.status === 'done' && <button onClick={(e) => { e.stopPropagation(); setSelectedStudentForProgress({id: r.studentId, name: r.studentName}); }} className="text-[10px] font-black uppercase bg-stone-800 text-stone-400 px-4 py-2 rounded-xl border border-stone-700/50 hover:bg-sky-500 hover:text-white hover:border-sky-400 transition-all shadow-sm">데이터 트래킹</button>}
                         {r.status === 'loading' ? (
                            <div className="flex items-center space-x-2 px-3 py-1.5 bg-sky-900/20 rounded-full border border-sky-500/20">
                              <span className="text-[10px] text-sky-400 font-black uppercase tracking-widest animate-pulse">{r.progressMessage}</span>
                            </div>
                         ) : 
                          r.status === 'done' ? <CheckCircleIcon className="w-7 h-7 text-green-500" /> : <ExclamationCircleIcon className="w-7 h-7 text-red-500" />}
                      </div>
                    </summary>
                    <div className="border-t border-stone-800/40 bg-stone-950/30">
                      {r.status === 'done' && r.data && <ReportDisplay reportData={r.data} />}
                      {r.status === 'error' && <div className="p-12 text-center"><p className="text-red-400 text-sm font-black uppercase mb-3">Analysis Failed</p><p className="text-stone-500 text-xs leading-relaxed max-w-xs mx-auto">{r.error}</p></div>}
                    </div>
                  </details>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      {selectedStudentForProgress && (
        <div className="fixed inset-0 bg-[#0c0a09]/95 backdrop-blur-2xl z-50 flex items-center justify-center p-8 animate-in fade-in duration-500">
