    let label = fullType;
    if (univ) label = label.replace(new RegExp(univ, 'gi'), '');
    if (year) label = label.replace(new RegExp(year, 'g'), '');
    return label.trim();
  };

  const handleSearchCriteria = useCallback(async (selectedRecord?: ExamDatabaseRecord) => {
    setIsSearching(true);
    const targetUniv = selectedRecord?.university || formData.university;
    const targetYear = selectedRecord?.year || formData.examYear;
    const targetType = selectedRecord?.problemType || formData.problemType;
    const model = formData.model;

    try {
      const problemMaterials: LinkedFile[] = [];
      const scoringMaterials: LinkedFile[] = [];

      if (selectedRecord) {
        const shortType = extractShortLabel(selectedRecord.problemType, targetUniv, targetYear);
        if (selectedRecord.problemUrl) {
          problemMaterials.push({ name: `${shortType} 문제 (URL)`, url: selectedRecord.problemUrl });
        }
        if (selectedRecord.solutionUrl) {
          scoringMaterials.push({ name: `${shortType} 해설 (URL)`, url: selectedRecord.solutionUrl });
        }
      }

      const criteria = await searchScoringCriteria(targetUniv, targetYear, targetType, model);

      setFormData(prev => ({ 
        ...prev, 
        university: targetUniv,
        examYear: targetYear,
        problemType: targetType,
        scoringCriteria: criteria,
        problemMaterials: problemMaterials.length > 0 ? [...problemMaterials, ...prev.problemMaterials.filter(p => !p.url)] : prev.problemMaterials,
        scoringMaterials: scoringMaterials.length > 0 ? [...scoringMaterials, ...prev.scoringMaterials.filter(s => !s.url)] : prev.scoringMaterials
      }));

    } catch (e) {
      console.error(e);
      alert("데이터 동기화 중 오류가 발생했습니다.");
    } finally {
      setIsSearching(false);
    }
  }, [formData]);

  const handleGenerateReport = useCallback(async () => {
    setIsLoading(true);
    const studentsToProcess = formData.students;
    const examInfo = `${formData.university} ${formData.examYear} ${formData.problemType}`.trim();

    setProgress({ current: 0, total: studentsToProcess.length });
    setResults(studentsToProcess.map(s => ({ studentId: s.id, studentName: s.name, status: 'loading', progressMessage: '준비 중...' })));

    for (let i = 0; i < studentsToProcess.length; i++) {
      const student = studentsToProcess[i];
      setProgress(prev => ({ ...prev, current: i + 1 }));

      try {
        const generationDate = new Date().toLocaleString('ko-KR');
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, progressMessage: 'AI 분석 중...' } : r));

        const rawReport = await gradeSolutionAndGenerateFeedback(
          { ...formData, scoringCriteria: formData.scoringCriteria },
          { name: student.name, solutionFiles: student.solutionFiles, reportTemplate: student.reportTemplate }
        );

        const htmlReport = await formatReportToHtml(
          rawReport,
          { ...formData },
          student.name,
          generationDate
        );

        const extracted = await extractReportData(rawReport, formData.model);
        saveToGoogleSheets({
          studentId: student.id, studentName: student.name, date: generationDate, examInfo: examInfo,
          ...extracted
        });

        const reportData: ReportData = {
          htmlContent: htmlReport,
          studentEmail: student.email,
          studentName: student.name,
          examInfo: examInfo,
          generationDate
        };

        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'done', data: reportData, progressMessage: undefined } : r));
      } catch (e) {
        const message = e instanceof Error ? e.message : '오류 발생';
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'error', error: message, progressMessage: undefined } : r));
      }
    }
    setIsLoading(false);
  }, [formData]);

  const handleFormChange = (newFormData: Partial<FormData>) => setFormData(prev => ({ ...prev, ...newFormData }));

  if (!isStarted) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 text-center animate-in fade-in duration-1000">
        <div className="max-w-3xl space-y-8">
          <div className="inline-block px-4 py-1.5 bg-sky-500/10 border border-sky-500/20 rounded-full text-sky-400 text-xs font-black uppercase tracking-widest mb-4">
             Future of Math Education
          </div>
          <h1 className="text-6xl md:text-8xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-br from-white via-stone-300 to-stone-500">
            MATH LOGIC AI
          </h1>
          <p className="text-xl text-stone-400 font-medium leading-relaxed max-w-2xl mx-auto">
            수리논술 채점의 패러다임을 바꿉니다. <br/>
            AI 정밀 분석을 통한 완벽한 평가 보고서와 성취도 트래킹 솔루션.
          </p>
          <div className="flex flex-col md:flex-row items-center justify-center gap-4 pt-8">
            <button 
              onClick={() => setIsStarted(true)}
              className="px-10 py-5 bg-white text-black font-black text-xl rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-2xl shadow-white/10"
            >
              분석 센터 입장하기
            </button>
            <div className="flex items-center space-x-6 text-stone-500 text-sm font-bold">
              <span>✓ AI 정밀 채점</span>
              <span>✓ 성취도 트래킹</span>
              <span>✓ PDF 리포트</span>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen w-full font-sans flex flex-col bg-[#0c0a09] text-stone-300 animate-in fade-in duration-500">
      <header className="sticky top-0 z-10 bg-[#0c0a09]/80 backdrop-blur-3xl border-b border-stone-800/40">
        <div className="container mx-auto px-8 py-5 flex justify-between items-center max-w-[1500px]">
          <div className="flex items-center space-x-4">
            <button onClick={() => setIsStarted(false)} className="text-2xl font-black tracking-tighter hover:text-white transition-colors">
              MATHLOGIC <span className="text-sky-500">AI</span>
            </button>
          </div>
          <div className="flex items-center space-x-6">
             <div className="flex items-center bg-stone-900 border border-stone-800 px-4 py-1.5 rounded-xl shadow-inner">
                <div className="w-2 h-2 bg-green-500 rounded-full mr-3 animate-pulse"></div>
                <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Premium Account</span>
             </div>
             <div className="w-10 h-10 rounded-full bg-gradient-to-br from-sky-500 to-indigo-600 border border-white/20"></div>
          </div>
        </div>
      </header>

      <main className="container mx-auto p-8 grid grid-cols-1 xl:grid-cols-12 gap-10 flex-grow items-start max-w-[1500px]">
        <div className="xl:col-span-5 lg:sticky top-32">
          <InputForm
            formData={formData}
            onFormChange={handleFormChange}
            onGenerate={handleGenerateReport}
            onSearchCriteria={handleSearchCriteria}
            isLoading={isLoading}
            isSearching={isSearching}
          />
        </div>
        <div className="xl:col-span-7 space-y-8">
          {results.length === 0 ? <ReportPlaceholder /> : (
            <div className="bg-stone-900/40 border border-stone-800/50 rounded-[3rem] shadow-3xl overflow-hidden backdrop-blur-2xl transition-all">
              <div className="p-10 border-b border-stone-800/50 bg-stone-900/60 flex justify-between items-center">
                <div>
                   <h2 className="text-2xl font-black text-stone-100 uppercase tracking-tight">AI Analysis Console</h2>
                   <p className="text-xs text-stone-500 font-bold mt-1">Real-time grading and reporting system</p>
                </div>
                <div className="flex items-center space-x-4">
                  <span className="px-5 py-2 bg-stone-950/80 rounded-2xl border border-stone-800 text-xs font-black text-sky-500">
                    {progress.current} / {progress.total}
                  </span>
                </div>
              </div>
              <div className="p-8 space-y-6">
                {results.map(r => (
                  <details key={r.studentId} className="bg-stone-900/80 border border-stone-800/40 rounded-[2rem] overflow-hidden group transition-all" open={r.status !== 'loading'}>
                    <summary className="p-6 flex justify-between items-center cursor-pointer hover:bg-stone-800/30 transition-all list-none select-none">
                      <div className="flex items-center space-x-5">
                        <div className="w-14 h-14 rounded-[1.25rem] bg-stone-950 border border-stone-800 flex items-center justify-center font-black text-stone-400 text-xl group-open:text-sky-400 group-open:border-sky-500/20 transition-all">
                          {r.studentName.slice(0, 1)}
                        </div>
                        <div>
                          <p className="font-black text-stone-100 text-lg">{r.studentName}</p>
                          <p className="text-[10px] text-stone-600 uppercase font-black tracking-widest">{r.status === 'done' ? 'Analysis Complete' : 'Processing...'}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-4">
                         {r.status === 'done' && <button onClick={(e) => { e.stopPropagation(); setSelectedStudentForProgress({id: r.studentId, name: r.studentName}); }} className="text-[10px] font-black uppercase bg-sky-500 text-white px-5 py-2.5 rounded-xl hover:bg-sky-400 transition-all shadow-lg shadow-sky-900/20">성취도 트래킹</button>}
                         {r.status === 'loading' ? (
                            <div className="flex items-center space-x-3 px-4 py-2 bg-stone-950/50 rounded-full border border-stone-800">
                              <LoadingSpinnerIcon className="w-4 h-4 text-sky-500 animate-spin" />
                              <span className="text-[10px] text-sky-400 font-black uppercase tracking-widest animate-pulse">{r.progressMessage}</span>
                            </div>
                         ) : 
                          r.status === 'done' ? <CheckCircleIcon className="w-8 h-8 text-green-500" /> : <ExclamationCircleIcon className="w-8 h-8 text-red-500" />}
                      </div>
                    </summary>
                    <div className="border-t border-stone-800/40 bg-[#0c0a09]/50">
                      {r.status === 'done' && r.data && <ReportDisplay reportData={r.data} />}
                      {r.status === 'error' && <div className="p-16 text-center"><p className="text-red-400 text-sm font-black uppercase mb-3">Analysis Failed</p><p className="text-stone-500 text-xs leading-relaxed max-w-sm mx-auto">{r.error}</p></div>}
                    </div>
                  </details>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      {selectedStudentForProgress && (
        <div className="fixed inset-0 bg-stone-950/95 backdrop-blur-3xl z-50 flex items-center justify-center p-8 animate-in zoom-in duration-300">
           <div className="bg-stone-900 border border-stone-800 w-full max-w-5xl max-h-[90vh] overflow-hidden rounded-[3.5rem] shadow-3xl flex flex-col">
              <div className="p-10 border-b border-stone-800/80 flex justify-between items-center bg-stone-900/50">
                 <div className="flex items-center space-x-6">
                    <div className="w-16 h-16 bg-gradient-to-tr from-sky-500 to-indigo-600 rounded-3xl flex items-center justify-center text-3xl font-black text-white shadow-xl">
                      {selectedStudentForProgress.name.slice(0, 1)}
                    </div>
                    <div>
                      <h2 className="text-3xl font-black text-stone-100 tracking-tight">{selectedStudentForProgress.name} 학생 분석</h2>
                      <p className="text-xs text-stone-500 font-black uppercase tracking-widest mt-1">Deep Learning Performance tracking</p>
