                 </div>
                 <button onClick={() => setSelectedStudentForProgress(null)} className="w-14 h-14 rounded-2xl bg-stone-800 text-stone-400 hover:bg-red-500/10 hover:text-red-500 flex items-center justify-center transition-all border border-stone-700/50">
                   <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                 </button>
              </div>
              <div className="p-12 overflow-y-auto bg-stone-950/50 scrollbar-thin">
                 <StudentProgressView studentId={selectedStudentForProgress.id} studentName={selectedStudentForProgress.name} />
              </div>
           </div>
        </div>
      )}

      <footer className="p-8 text-center border-t border-stone-900/50 text-[10px] font-bold text-stone-600 uppercase tracking-[0.3em]">
         © 2025 MATHLOGIC AI DIGITAL SERVICES • ALL RIGHTS RESERVED
      </footer>
    </div>
  );
};

