import React, { useState, useMemo } from 'react';
import type { FormData, ModelName, LinkedFile, ExamDatabaseRecord } from '../types';
import { UploadIcon } from './icons/UploadIcon';
import { TrashIcon } from './icons/TrashIcon';
import { AVAILABLE_MODELS } from '../constants';
import { SearchIcon } from './icons/SearchIcon';
import { LoadingSpinnerIcon } from './icons/LoadingSpinnerIcon';
import { PlusCircleIcon } from './icons/PlusCircleIcon';
import { LinkIcon } from './icons/LinkIcon';

interface InputFormProps {
  formData: FormData;
  onFormChange: (newFormData: Partial<FormData>) => void;
  onGenerate: () => void;
  onSearchCriteria: (selectedRecord?: ExamDatabaseRecord) => void;
  isLoading: boolean;
  isSearching: boolean;
}

const modelLabels: Record<ModelName, string> = {
  'gemini-2.5-flash': 'Standard Engine',
  'gemini-2.5-pro': 'Professional Engine',
  'gemini-3-flash-preview': 'v3.0 Lite',
  'gemini-3-pro-preview': 'v3.0 Ultra',
};

const extractCleanLabel = (fullType: string, univ: string, year: string) => {
  if (!fullType) return '기타 유형';
  let label = fullType;
  if (univ) label = label.replace(new RegExp(univ.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi'), '');
  if (year) label = label.replace(new RegExp(year, 'g'), '');
  return label.trim() || fullType;
};

const MaterialBox: React.FC<{
  label: string;
  files: LinkedFile[];
  onFilesChange: (files: LinkedFile[]) => void;
  description: string;
  icon: React.ReactNode;
}> = ({ label, files, onFilesChange, description, icon }) => {
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).map((f: File) => ({ name: f.name, file: f }));
      onFilesChange([...files, ...newFiles]);
    }
  };

  return (
    <div className="bg-stone-900 border border-stone-800 rounded-3xl p-6 flex flex-col h-full group transition-all hover:bg-stone-800/40">
      <div className="flex justify-between items-start mb-6">
        <div className="flex items-center space-x-4">
          <div className="p-3 bg-stone-950 rounded-2xl text-stone-500 group-hover:text-sky-500 transition-colors shadow-inner">
            {icon}
          </div>
          <div>
            <h4 className="text-sm font-black text-stone-200 uppercase tracking-tight">{label}</h4>
            <p className="text-[10px] text-stone-500 font-bold">{description}</p>
          </div>
        </div>
        <label className="cursor-pointer bg-white/5 hover:bg-white/10 text-white/60 hover:text-white border border-white/10 px-4 py-2 rounded-xl text-[10px] font-black transition-all flex items-center">
          <UploadIcon className="w-3.5 h-3.5 mr-2" /> 로드
          <input type="file" className="sr-only" onChange={handleFileUpload} multiple accept=".pdf,.png,.jpg,.jpeg" />
        </label>
      </div>

      <div className="flex-grow space-y-2 overflow-y-auto max-h-48 min-h-[120px] scrollbar-thin pr-2">
        {files.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center border-2 border-dashed border-stone-800 rounded-2xl py-8 opacity-30">
            <span className="text-[10px] text-stone-600 font-black uppercase">No Data Linked</span>
          </div>
        ) : (
          files.map((f, i) => (
            <div key={i} className="flex items-center justify-between bg-stone-950/50 border border-stone-800 px-4 py-3 rounded-2xl group/item hover:border-stone-700 transition-all">
              <div className="flex items-center min-w-0 flex-1 mr-3">
                {f.url ? <LinkIcon className="w-4 h-4 text-sky-500 mr-3 shrink-0" /> : <div className="w-2 h-2 rounded-full bg-stone-700 mr-3 shrink-0" />}
                {f.url ? (
                  <a href={f.url} target="_blank" rel="noreferrer" className="text-xs text-stone-300 hover:text-sky-400 truncate underline decoration-stone-800 underline-offset-4">{f.name}</a>
                ) : (
                  <span className="text-xs text-stone-400 truncate">{f.name}</span>
                )}
              </div>
              <button onClick={() => onFilesChange(files.filter((_, idx) => idx !== i))} className="text-stone-700 hover:text-red-500 transition-colors p-1">
                <TrashIcon className="w-4 h-4" />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export const InputForm: React.FC<InputFormProps> = ({ formData, onFormChange, onGenerate, onSearchCriteria, isLoading, isSearching }) => {
  const [isAdminOpen, setIsAdminOpen] = useState(false);

  const availableRecords = useMemo(() => {
    if (!formData.university && !formData.examYear) return [];
    const dbStr = localStorage.getItem('exam_database');
    if (!dbStr) return [];
    const db: ExamDatabaseRecord[] = JSON.parse(dbStr);

    return db.filter(r => {
      const univMatch = formData.university && r.university.toLowerCase().includes(formData.university.toLowerCase());
      const yearMatch = formData.examYear && r.year.toString().includes(formData.examYear);
      return univMatch && yearMatch;
    });
  }, [formData.university, formData.examYear]);

  const handleCsvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const text = ev.target?.result as string;
        const rows = text.split(/\r?\n/).filter(r => r.trim()).slice(1);
        const db = rows.map(row => {
          const parts = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || row.split(',').map(s => s.trim());
          const cleanedParts = parts.map(p => p.replace(/^"|"$/g, '').trim());
          const [univ, year, pType, pUrl, sUrl] = cleanedParts;
          return { university: univ || '', year: year || '', problemType: pType || '', problemUrl: pUrl || '', solutionUrl: sUrl || '' };
        });
        localStorage.setItem('exam_database', JSON.stringify(db));
        alert('Database Updated');
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="bg-stone-900/40 border border-stone-800/60 p-10 rounded-[4rem] shadow-4xl backdrop-blur-3xl space-y-10">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-black text-stone-100 flex items-center tracking-tighter">
          Config <span className="text-sky-500 ml-2">Center</span>
        </h2>
        <div className="flex items-center space-x-3">
          <select 
            value={formData.model}
            onChange={(e) => onFormChange({ model: e.target.value as ModelName })}
            className="bg-stone-950 text-[10px] font-black text-stone-400 border border-stone-800 px-5 py-2.5 rounded-2xl outline-none cursor-pointer hover:text-white transition shadow-inner"
          >
            {AVAILABLE_MODELS.map(m => (
              <option key={m} value={m} className="bg-stone-950">{modelLabels[m]}</option>
            ))}
          </select>
          <button onClick={() => setIsAdminOpen(!isAdminOpen)} className="p-2.5 bg-stone-950 border border-stone-800 rounded-2xl text-stone-600 hover:text-stone-200 transition-all shadow-inner">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>
        </div>
      </div>

      {isAdminOpen && (
        <div className="p-6 bg-sky-500/5 border border-sky-500/10 rounded-3xl space-y-4 animate-in fade-in zoom-in duration-300">
          <p className="text-[10px] text-sky-500 font-black uppercase tracking-widest">Master Database Import (CSV)</p>
          <input type="file" accept=".csv" onChange={handleCsvUpload} className="text-[10px] text-stone-500 file:mr-4 file:py-2 file:px-6 file:rounded-xl file:border-0 file:text-[10px] file:font-black file:bg-sky-500 file:text-white hover:file:bg-sky-400 transition-all" />
        </div>
      )}

      <div className="grid grid-cols-2 gap-8">
        <div className="space-y-3">
          <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">University</label>
          <input
            type="text"
            value={formData.university}
            onChange={(e) => onFormChange({ university: e.target.value })}
            placeholder="예: 연세대학교"
            className="w-full px-6 py-4 bg-stone-950 border border-stone-800 rounded-3xl text-stone-100 text-sm focus:border-sky-500/50 outline-none transition shadow-inner"
          />
