              >
                <span>{extractCleanLabel(r.problemType, formData.university, formData.examYear)}</span>
                <SearchIcon className="w-4 h-4 opacity-30" />
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <MaterialBox
          label="Problem Sheet"
          files={formData.problemMaterials}
