          className="w-full h-48 px-8 py-6 bg-stone-950 border border-stone-800 rounded-[2.5rem] text-xs text-stone-300 focus:border-sky-500/50 outline-none transition leading-relaxed resize-none scrollbar-thin shadow-inner"
        />
