      <div className="border-t border-stone-800/50 pt-10">
        <div className="flex justify-between items-center mb-8">
          <h3 className="text-lg font-black text-stone-200 uppercase tracking-tighter">Students Queue</h3>
          <button onClick={() => onFormChange({ students: [...formData.students, { id: crypto.randomUUID(), name: '', email: '', solutionFiles: [], reportTemplate: '' }] })} className="bg-white/5 hover:bg-white/10 border border-white/10 px-6 py-2.5 rounded-2xl text-[11px] font-black text-stone-300 transition-all flex items-center">
            <PlusCircleIcon className="w-4 h-4 mr-2 text-sky-500" /> 학생 등록
          </button>
