                  <input value={s.email} onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, email: e.target.value} : item) })} placeholder="이메일" className="bg-[#0c0a09] px-6 py-3 rounded-2xl border border-stone-800 text-xs text-stone-200 outline-none focus:border-sky-500/30 transition shadow-inner" />
