import { saveToGoogleSheets } from './services/googleSheetsService';
import React, { useState, useCallback, useEffect } from 'react';
import { InputForm } from './components/InputForm';
import { ReportDisplay } from './components/ReportDisplay';
import { ReportPlaceholder } from './components/ReportPlaceholder';
import { StudentProgressView } from './components/StudentProgressView';
import { gradeSolutionAndGenerateFeedback, formatReportToHtml, searchScoringCriteria, extractReportData } from './services/geminiService';
import type { FormData, ReportData, ExamDatabaseRecord, LinkedFile } from './types';
import { initialFormData } from './constants';
import { CheckCircleIcon } from './components/icons/CheckCircleIcon';
import { ExclamationCircleIcon } from './components/icons/ExclamationCircleIcon';
import { LoadingSpinnerIcon } from './components/icons/LoadingSpinnerIcon';

interface ReportResult {
  status: 'loading' | 'done' | 'error';
  data?: ReportData;
  error?: string;
  studentName: string;
  studentId: string;
  progressMessage?: string;
}

const App: React.FC = () => {
  const [formData, setFormData] = useState<FormData>(initialFormData);
  const [results, setResults] = useState<ReportResult[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSearching, setIsSearching] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [selectedStudentForProgress, setSelectedStudentForProgress] = useState<{ id: string, name: string } | null>(null);

  // 비즈니스 로직 상태
  const [isStarted, setIsStarted] = useState(false);
  const [licenseKey, setLicenseKey] = useState('');
  const [isVerified, setIsVerified] = useState(false);

  // 라이선스 인증 시뮬레이션 (본사가 발급한 코드라고 가정)
  const verifyLicense = () => {
    if (licenseKey === 'MATHLOGIC-2025-PREMIUM') {
      setIsVerified(true);
      setIsStarted(true);
      alert('프리미엄 서비스 인증에 성공했습니다. 중앙 데이터베이스를 활성화합니다.');
    } else if (licenseKey === 'GUEST') {
      setIsVerified(false);
      setIsStarted(true);
    } else {
      alert('유효하지 않은 인증 코드입니다.');
    }
  };

  const extractShortLabel = (fullType: string, univ: string, year: string) => {
    if (!fullType) return '유형';
    let label = fullType;
    if (univ) label = label.replace(new RegExp(univ, 'gi'), '');
    if (year) label = label.replace(new RegExp(year, 'g'), '');
    return label.trim();
  };

  const handleSearchCriteria = useCallback(async (selectedRecord?: ExamDatabaseRecord) => {
    setIsSearching(true);
    const targetUniv = selectedRecord?.university || formData.university;
    const targetYear = selectedRecord?.year || formData.examYear;
    const targetType = selectedRecord?.problemType || formData.problemType;

    try {
      const problemMaterials: LinkedFile[] = [];
      const scoringMaterials: LinkedFile[] = [];

      if (selectedRecord) {
        const shortType = extractShortLabel(selectedRecord.problemType, targetUniv, targetYear);
        if (selectedRecord.problemUrl) {
          problemMaterials.push({ name: `${shortType} 문제 (중앙 DB)`, url: selectedRecord.problemUrl });
        }
        if (selectedRecord.solutionUrl) {
          scoringMaterials.push({ name: `${shortType} 해설 (중앙 DB)`, url: selectedRecord.solutionUrl });
        }
      }

      // 중앙 DB를 사용하는 경우 검색 생략하거나 보강 가능
      const criteria = await searchScoringCriteria(targetUniv, targetYear, targetType, formData.model);

      setFormData(prev => ({ 
        ...prev, 
        university: targetUniv,
        examYear: targetYear,
        problemType: targetType,
        scoringCriteria: criteria,
        problemMaterials: problemMaterials.length > 0 ? [...problemMaterials] : prev.problemMaterials,
        scoringMaterials: scoringMaterials.length > 0 ? [...scoringMaterials] : prev.scoringMaterials
      }));

    } catch (e) {
      console.error(e);
      alert("데이터 동기화 중 오류가 발생했습니다.");
    } finally {
      setIsSearching(false);
    }
  }, [formData.model, formData.university, formData.examYear, formData.problemType]);

  const handleGenerateReport = useCallback(async () => {
    setIsLoading(true);
    const studentsToProcess = formData.students;
    const examInfo = `${formData.university} ${formData.examYear} ${formData.problemType}`.trim();

    setProgress({ current: 0, total: studentsToProcess.length });
    setResults(studentsToProcess.map(s => ({ studentId: s.id, studentName: s.name, status: 'loading', progressMessage: '서버 분석 대기 중...' })));

    for (let i = 0; i < studentsToProcess.length; i++) {
      const student = studentsToProcess[i];
      setProgress(prev => ({ ...prev, current: i + 1 }));

      try {
        const generationDate = new Date().toLocaleString('ko-KR');
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, progressMessage: 'AI 정밀 채점 중...' } : r));

        const rawReport = await gradeSolutionAndGenerateFeedback(
          { ...formData },
          { name: student.name, solutionFiles: student.solutionFiles, reportTemplate: student.reportTemplate }
        );

        const htmlReport = await formatReportToHtml(
          rawReport,
          { ...formData },
          student.name,
          generationDate
        );

        const extracted = await extractReportData(rawReport, formData.model);
        saveToGoogleSheets({
          studentId: student.id, studentName: student.name, date: generationDate, examInfo: examInfo,
          ...extracted
        });

        const reportData: ReportData = {
          htmlContent: htmlReport,
          studentEmail: student.email,
          studentName: student.name,
          examInfo: examInfo,
          generationDate
        };

        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'done', data: reportData, progressMessage: undefined } : r));
      } catch (e) {
        setResults(prev => prev.map(r => r.studentId === student.id ? { ...r, status: 'error', error: '분석 중 오류 발생', progressMessage: undefined } : r));
      }
    }
    setIsLoading(false);
  }, [formData]);

  const handleFormChange = (newFormData: Partial<FormData>) => setFormData(prev => ({ ...prev, ...newFormData }));

  if (!isStarted) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-8 bg-[#0c0a09] animate-in fade-in duration-1000">
        <div className="w-full max-w-xl space-y-12">
          <div className="text-center space-y-4">
             <div className="inline-block px-4 py-1 bg-sky-500/10 border border-sky-500/20 rounded-full text-sky-400 text-[10px] font-black tracking-widest uppercase mb-4">
                Enterprise Solution v2.5
             </div>
             <h1 className="text-7xl font-black tracking-tighter text-white">
               MATHLOGIC <span className="text-transparent bg-clip-text bg-gradient-to-r from-sky-400 to-indigo-500">AI</span>
             </h1>
             <p className="text-stone-500 font-bold">지점 및 파트너사를 위한 수리논술 통합 관리 시스템</p>
          </div>

          <div className="bg-stone-900 border border-stone-800 p-10 rounded-[3rem] shadow-4xl space-y-8">
             <div className="space-y-3">
                <label className="text-[10px] font-black text-stone-500 uppercase tracking-widest ml-1">Service Access Key</label>
                <input 
                  type="password"
                  value={licenseKey}
                  onChange={(e) => setLicenseKey(e.target.value)}
                  placeholder="본사 발급 코드를 입력하세요"
                  className="w-full px-8 py-5 bg-stone-950 border border-stone-800 rounded-3xl text-white outline-none focus:border-sky-500/50 transition-all text-center tracking-widest font-black"
                />
             </div>
             <button 
                onClick={verifyLicense}
                className="w-full py-5 bg-white text-black font-black text-lg rounded-3xl hover:bg-stone-200 transition-all shadow-2xl shadow-white/5"
             >
                시스템 접속
             </button>
             <p className="text-center text-[10px] text-stone-600 font-bold uppercase tracking-tight">
                * 인증 코드 문의: admin@mathlogic.ai
             </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen w-full font-sans flex flex-col bg-[#0c0a09] text-stone-300 animate-in fade-in duration-500">
      <header className="sticky top-0 z-10 bg-[#0c0a09]/80 backdrop-blur-3xl border-b border-stone-800/40">
        <div className="container mx-auto px-10 py-6 flex justify-between items-center max-w-[1600px]">
          <div className="flex items-center space-x-4">
            <button onClick={() => setIsStarted(false)} className="text-2xl font-black tracking-tighter group">
              MATHLOGIC <span className="text-sky-500 group-hover:text-sky-400 transition-colors">AI</span>
            </button>
            <div className="h-4 w-[1px] bg-stone-800 mx-2"></div>
            <span className="text-[10px] font-black text-stone-500 uppercase tracking-widest">
              {isVerified ? 'Partner Node: HQ Central' : 'Guest Access'}
            </span>
          </div>
          <div className="flex items-center space-x-6">
             <div className="hidden md:flex items-center bg-stone-900 border border-stone-800 px-5 py-2 rounded-2xl">
                <div className="w-2 h-2 bg-sky-500 rounded-full mr-3 shadow-[0_0_8px_rgba(14,165,233,0.8)]"></div>
                <span className="text-[10px] font-black text-stone-300 uppercase tracking-widest">System Online</span>
             </div>
             <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-stone-800 to-stone-900 border border-stone-700 flex items-center justify-center font-black text-sky-500 shadow-inner">
                {isVerified ? 'HQ' : 'GT'}
             </div>
          </div>
        </div>
      </header>

      <main className="container mx-auto p-10 grid grid-cols-1 xl:grid-cols-12 gap-12 flex-grow items-start max-w-[1600px]">
        <div className="xl:col-span-5 lg:sticky top-36">
          <InputForm
            formData={formData}
            onFormChange={handleFormChange}
            onGenerate={handleGenerateReport}
            onSearchCriteria={handleSearchCriteria}
            isLoading={isLoading}
            isSearching={isSearching}
          />
        </div>
        <div className="xl:col-span-7 space-y-10">
          {results.length === 0 ? <ReportPlaceholder /> : (
            <div className="bg-stone-900/40 border border-stone-800/50 rounded-[4rem] shadow-4xl overflow-hidden backdrop-blur-3xl">
              <div className="p-12 border-b border-stone-800/50 bg-stone-900/60 flex justify-between items-end">
                <div>
                   <h2 className="text-3xl font-black text-stone-100 tracking-tighter uppercase">Grading Console</h2>
                   <p className="text-xs text-stone-500 font-bold mt-2 uppercase tracking-widest">AI analysis in progress for {formData.students.length} students</p>
                </div>
                <div className="px-6 py-2 bg-sky-500/10 rounded-2xl border border-sky-500/20 text-xs font-black text-sky-400">
                  {progress.current} / {progress.total} COMPLETE
                </div>
              </div>
              <div className="p-10 space-y-8">
                {results.map(r => (
                  <details key={r.studentId} className="bg-stone-900/80 border border-stone-800/40 rounded-[2.5rem] overflow-hidden group transition-all" open={r.status !== 'loading'}>
                    <summary className="p-8 flex justify-between items-center cursor-pointer hover:bg-stone-800/30 transition-all list-none select-none">
                      <div className="flex items-center space-x-6">
                        <div className="w-16 h-16 rounded-3xl bg-stone-950 border border-stone-800 flex items-center justify-center font-black text-stone-400 text-2xl group-open:text-sky-400 group-open:border-sky-500/20 transition-all shadow-inner">
                          {r.studentName.slice(0, 1)}
                        </div>
                        <div>
                          <p className="font-black text-stone-100 text-xl tracking-tight">{r.studentName}</p>
                          <p className="text-[10px] text-stone-600 uppercase font-black tracking-[0.2em] mt-1">{r.status === 'done' ? 'Reporting Ready' : 'Processing'}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-6">
                         {r.status === 'done' && <button onClick={(e) => { e.stopPropagation(); setSelectedStudentForProgress({id: r.studentId, name: r.studentName}); }} className="px-6 py-3 bg-sky-600 text-white font-black text-[11px] rounded-2xl hover:bg-sky-500 transition-all shadow-xl shadow-sky-900/30 uppercase tracking-widest">상담용 통계</button>}
                         {r.status === 'loading' ? (
                            <div className="flex items-center space-x-4 px-5 py-2.5 bg-stone-950/80 rounded-2xl border border-stone-800">
                              <LoadingSpinnerIcon className="w-4 h-4 text-sky-500 animate-spin" />
                              <span className="text-[10px] text-sky-400 font-black uppercase tracking-widest animate-pulse">{r.progressMessage}</span>
                            </div>
                         ) : 
                          r.status === 'done' ? <CheckCircleIcon className="w-10 h-10 text-green-500" /> : <ExclamationCircleIcon className="w-10 h-10 text-red-500" />}
                      </div>
                    </summary>
                    <div className="border-t border-stone-800/40 bg-stone-950/40">
                      {r.status === 'done' && r.data && <ReportDisplay reportData={r.data} />}
                    </div>
                  </details>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      {selectedStudentForProgress && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-3xl z-50 flex items-center justify-center p-12 animate-in fade-in zoom-in duration-300">
           <div className="bg-stone-900 border border-stone-800 w-full max-w-6xl max-h-[90vh] overflow-hidden rounded-[4rem] shadow-4xl flex flex-col">
              <div className="p-12 border-b border-stone-800/80 flex justify-between items-center bg-stone-900/50">
                 <div className="flex items-center space-x-8">
                    <div className="w-20 h-20 bg-gradient-to-tr from-sky-500 to-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl font-black text-white shadow-2xl">
                      {selectedStudentForProgress.name.slice(0, 1)}
                    </div>
                    <div>
                      <h2 className="text-4xl font-black text-stone-100 tracking-tighter">{selectedStudentForProgress.name} 학생 성과 지표</h2>
                      <p className="text-xs text-stone-500 font-black uppercase tracking-[0.3em] mt-2">Personalized Performance Intelligence</p>
                    </div>
                 </div>
                 <button onClick={() => setSelectedStudentForProgress(null)} className="w-16 h-16 rounded-[1.5rem] bg-stone-800 text-stone-500 hover:bg-red-500/10 hover:text-red-500 flex items-center justify-center transition-all border border-stone-700/50">
                   <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                 </button>
              </div>
              <div className="p-16 overflow-y-auto bg-stone-950/30 scrollbar-thin">
                 <StudentProgressView studentId={selectedStudentForProgress.id} studentName={selectedStudentForProgress.name} />
              </div>
           </div>
        </div>
      )}

      <footer className="p-12 text-center border-t border-stone-900/50 text-[10px] font-black text-stone-700 uppercase tracking-[0.5em]">
         MathLogic AI Enterprise Solution • Restricted Access for Partners only
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import type { FormData, ModelName, LinkedFile, ExamDatabaseRecord } from '../types';
import { UploadIcon } from './icons/UploadIcon';
import { TrashIcon } from './icons/TrashIcon';
import { AVAILABLE_MODELS } from '../constants';
import { SearchIcon } from './icons/SearchIcon';
import { LoadingSpinnerIcon } from './icons/LoadingSpinnerIcon';
import { PlusCircleIcon } from './icons/PlusCircleIcon';
import { LinkIcon } from './icons/LinkIcon';

interface InputFormProps {
  formData: FormData;
  onFormChange: (newFormData: Partial<FormData>) => void;
  onGenerate: () => void;
  onSearchCriteria: (selectedRecord?: ExamDatabaseRecord) => void;
  isLoading: boolean;
  isSearching: boolean;
}

const modelLabels: Record<ModelName, string> = {
  'gemini-2.5-flash': 'Standard AI',
  'gemini-2.5-pro': 'Professional AI',
  'gemini-3-flash-preview': 'v3.0 Ultra-Fast',
  'gemini-3-pro-preview': 'v3.0 Extreme',
};

const extractCleanLabel = (fullType: string, univ: string, year: string) => {
  if (!fullType) return '기타 유형';
  let label = fullType;
  if (univ) label = label.replace(new RegExp(univ.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi'), '');
  if (year) label = label.replace(new RegExp(year, 'g'), '');
  return label.trim() || fullType;
};

const MaterialBox: React.FC<{
  label: string;
  files: LinkedFile[];
  onFilesChange: (files: LinkedFile[]) => void;
  description: string;
  icon: React.ReactNode;
}> = ({ label, files, onFilesChange, description, icon }) => {
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newFiles = Array.from(e.target.files).map((f: File) => ({ name: f.name, file: f }));
      onFilesChange([...files, ...newFiles]);
    }
  };

  return (
    <div className="bg-stone-900 border border-stone-800 rounded-[2.5rem] p-8 flex flex-col h-full group transition-all hover:bg-stone-800/40">
      <div className="flex justify-between items-start mb-8">
        <div className="flex items-center space-x-5">
          <div className="p-4 bg-stone-950 rounded-[1.5rem] text-stone-600 group-hover:text-sky-500 transition-colors shadow-inner">
            {icon}
          </div>
          <div>
            <h4 className="text-sm font-black text-stone-200 uppercase tracking-tight">{label}</h4>
            <p className="text-[10px] text-stone-600 font-bold uppercase mt-1">{description}</p>
          </div>
        </div>
        <label className="cursor-pointer bg-white/5 hover:bg-white/10 text-white/40 hover:text-white border border-white/10 px-5 py-2.5 rounded-2xl text-[10px] font-black transition-all flex items-center uppercase tracking-widest">
          <UploadIcon className="w-4 h-4 mr-2" /> Load
          <input type="file" className="sr-only" onChange={handleFileUpload} multiple accept=".pdf,.png,.jpg,.jpeg" />
        </label>
      </div>

      <div className="flex-grow space-y-3 overflow-y-auto max-h-56 min-h-[140px] scrollbar-thin pr-3">
        {files.length === 0 ? (
          <div className="h-full flex flex-col items-center justify-center border-2 border-dashed border-stone-800 rounded-[2rem] py-10 opacity-20">
            <span className="text-[10px] text-stone-500 font-black uppercase tracking-[0.2em]">Ready for Data</span>
          </div>
        ) : (
          files.map((f, i) => (
            <div key={i} className="flex items-center justify-between bg-stone-950/60 border border-stone-800 px-5 py-4 rounded-2xl group/item hover:border-stone-600 transition-all">
              <div className="flex items-center min-w-0 flex-1 mr-4">
                {f.url ? <LinkIcon className="w-4 h-4 text-sky-500 mr-4 shrink-0" /> : <div className="w-2 h-2 rounded-full bg-stone-700 mr-4 shrink-0" />}
                <span className={`text-xs truncate ${f.url ? 'text-sky-400 font-black' : 'text-stone-400 font-bold'}`}>{f.name}</span>
              </div>
              <button onClick={() => onFilesChange(files.filter((_, idx) => idx !== i))} className="text-stone-700 hover:text-red-500 transition-colors p-1">
                <TrashIcon className="w-4 h-4" />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export const InputForm: React.FC<InputFormProps> = ({ formData, onFormChange, onGenerate, onSearchCriteria, isLoading, isSearching }) => {
  const [isAdminOpen, setIsAdminOpen] = useState(false);

  const availableRecords = useMemo(() => {
    if (!formData.university && !formData.examYear) return [];
    const dbStr = localStorage.getItem('exam_database');
    if (!dbStr) return [];
    const db: ExamDatabaseRecord[] = JSON.parse(dbStr);

    return db.filter(r => {
      const univMatch = formData.university && r.university.toLowerCase().includes(formData.university.toLowerCase());
      const yearMatch = formData.examYear && r.year.toString().includes(formData.examYear);
      return univMatch && yearMatch;
    });
  }, [formData.university, formData.examYear]);

  const handleCsvUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const text = ev.target?.result as string;
        const rows = text.split(/\r?\n/).filter(r => r.trim()).slice(1);
        const db = rows.map(row => {
          const parts = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g) || row.split(',').map(s => s.trim());
          const cleanedParts = parts.map(p => p.replace(/^"|"$/g, '').trim());
          const [univ, year, pType, pUrl, sUrl] = cleanedParts;
          return { university: univ || '', year: year || '', problemType: pType || '', problemUrl: pUrl || '', solutionUrl: sUrl || '' };
        });
        localStorage.setItem('exam_database', JSON.stringify(db));
        alert('중앙 데이터베이스가 성공적으로 업데이트되었습니다.');
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="bg-stone-900/40 border border-stone-800/60 p-12 rounded-[5rem] shadow-5xl backdrop-blur-3xl space-y-12">
      <div className="flex justify-between items-center">
        <div>
           <h2 className="text-4xl font-black text-stone-100 tracking-tighter uppercase">Setup</h2>
           <p className="text-[10px] text-stone-600 font-black tracking-widest uppercase mt-1">Configure Analysis Parameters</p>
        </div>
        <div className="flex items-center space-x-4">
          <select 
            value={formData.model}
            onChange={(e) => onFormChange({ model: e.target.value as ModelName })}
            className="bg-stone-950 text-[10px] font-black text-stone-500 border border-stone-800 px-6 py-3 rounded-2xl outline-none cursor-pointer hover:text-sky-400 transition-all shadow-inner uppercase tracking-widest"
          >
            {AVAILABLE_MODELS.map(m => (
              <option key={m} value={m} className="bg-stone-950">{modelLabels[m]}</option>
            ))}
          </select>
          <button onClick={() => setIsAdminOpen(!isAdminOpen)} className="p-3 bg-stone-950 border border-stone-800 rounded-2xl text-stone-600 hover:text-sky-500 transition-all shadow-inner">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
          </button>
        </div>
      </div>

      {isAdminOpen && (
        <div className="p-8 bg-sky-500/5 border border-sky-500/10 rounded-[2.5rem] space-y-6 animate-in fade-in zoom-in duration-300">
          <div>
            <p className="text-[11px] text-sky-500 font-black uppercase tracking-widest">Master Database Management (CSV)</p>
            <p className="text-[10px] text-stone-600 font-bold mt-1 uppercase">Central control for all branch assets</p>
          </div>
          <input type="file" accept=".csv" onChange={handleCsvUpload} className="text-[11px] text-stone-500 file:mr-6 file:py-3 file:px-8 file:rounded-2xl file:border-0 file:text-[11px] file:font-black file:bg-sky-500 file:text-white hover:file:bg-sky-400 transition-all shadow-xl" />
        </div>
      )}

      <div className="grid grid-cols-2 gap-10">
        <div className="space-y-4">
          <label className="text-[10px] font-black text-stone-600 uppercase tracking-widest ml-1">Target University</label>
          <input
            type="text"
            value={formData.university}
            onChange={(e) => onFormChange({ university: e.target.value })}
            placeholder="예: 연세대학교"
            className="w-full px-8 py-5 bg-stone-950 border border-stone-800 rounded-3xl text-stone-100 text-sm font-bold focus:border-sky-500/50 outline-none transition shadow-inner"
          />
        </div>
        <div className="space-y-4">
          <label className="text-[10px] font-black text-stone-600 uppercase tracking-widest ml-1">Examination Year</label>
          <input
            type="text"
            value={formData.examYear}
            onChange={(e) => onFormChange({ examYear: e.target.value })}
            placeholder="예: 2025"
            className="w-full px-8 py-5 bg-stone-950 border border-stone-800 rounded-3xl text-stone-100 text-sm font-bold focus:border-sky-500/50 outline-none transition shadow-inner"
          />
        </div>
      </div>

      {availableRecords.length > 0 && (
        <div className="space-y-5 animate-in fade-in slide-in-from-top-4">
          <label className="text-[10px] font-black text-stone-600 uppercase tracking-widest ml-1">Central DB Assets Found</label>
          <div className="grid grid-cols-1 gap-3">
            {availableRecords.map((r, i) => (
              <button
                key={i}
                onClick={() => onSearchCriteria(r)}
                className={`w-full text-left px-8 py-5 rounded-[2rem] text-xs font-black transition-all border-2 flex justify-between items-center group ${
                  formData.problemType === r.problemType 
                  ? 'bg-sky-500/10 border-sky-500 text-sky-400 shadow-2xl shadow-sky-900/10' 
                  : 'bg-stone-950 border-stone-800 text-stone-500 hover:border-stone-700'
                }`}
              >
                <span>{extractCleanLabel(r.problemType, formData.university, formData.examYear)}</span>
                <div className={`w-2 h-2 rounded-full transition-all ${formData.problemType === r.problemType ? 'bg-sky-500 scale-150' : 'bg-stone-800 group-hover:bg-stone-600'}`}></div>
              </button>
            ))}
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        <MaterialBox
          label="Problem Data"
          files={formData.problemMaterials}
          onFilesChange={(fs) => onFormChange({ problemMaterials: fs })}
          description="Exam Resource"
          icon={<svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>}
        />
        <MaterialBox
          label="Scoring Matrix"
          files={formData.scoringMaterials}
          onFilesChange={(fs) => onFormChange({ scoringMaterials: fs })}
          description="Logic Guidelines"
          icon={<svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" /></svg>}
        />
      </div>

      <div className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <label className="text-[10px] font-black text-stone-600 uppercase tracking-[0.4em]">AI Derived Context</label>
          {isSearching && <LoadingSpinnerIcon className="w-5 h-5 text-sky-500 animate-spin" />}
        </div>
        <textarea
          value={formData.scoringCriteria}
          onChange={(e) => onFormChange({ scoringCriteria: e.target.value })}
          placeholder="데이터베이스를 선택하거나 텍스트를 입력하세요."
          className="w-full h-56 px-10 py-8 bg-stone-950 border border-stone-800 rounded-[3.5rem] text-xs text-stone-300 focus:border-sky-500/50 outline-none transition leading-relaxed resize-none scrollbar-thin shadow-inner"
        />
      </div>

      <div className="border-t border-stone-800/50 pt-12">
        <div className="flex justify-between items-center mb-10">
          <h3 className="text-xl font-black text-stone-200 uppercase tracking-tighter">Students Registry</h3>
          <button onClick={() => onFormChange({ students: [...formData.students, { id: crypto.randomUUID(), name: '', email: '', solutionFiles: [], reportTemplate: '' }] })} className="bg-white/5 hover:bg-white/10 border border-white/10 px-8 py-3 rounded-2xl text-[11px] font-black text-stone-200 transition-all flex items-center shadow-lg">
            <PlusCircleIcon className="w-5 h-5 mr-3 text-sky-500" /> New Student
          </button>
        </div>

        <div className="space-y-5 max-h-[25rem] overflow-y-auto pr-4 scrollbar-thin">
          {formData.students.length === 0 ? (
            <div className="text-center py-20 border-2 border-dashed border-stone-800 rounded-[4rem] opacity-20">
              <p className="text-[11px] text-stone-500 font-black uppercase tracking-[0.3em]">Registry Empty</p>
            </div>
          ) : (
            formData.students.map((s) => (
              <div key={s.id} className="p-8 bg-stone-950 border border-stone-800 rounded-[3rem] relative group hover:border-stone-600 transition-all shadow-inner">
                <button onClick={() => onFormChange({ students: formData.students.filter(std => std.id !== s.id) })} className="absolute top-8 right-8 text-stone-800 hover:text-red-500 transition-colors p-1">
                  <TrashIcon className="w-6 h-6" />
                </button>
                <div className="grid grid-cols-2 gap-6 mb-6">
                  <input value={s.name} onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, name: e.target.value} : item) })} placeholder="성함" className="bg-[#0c0a09] px-8 py-4 rounded-2xl border border-stone-800 text-xs text-stone-200 font-bold outline-none focus:border-sky-500/30 transition shadow-inner" />
                  <input value={s.email} onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, email: e.target.value} : item) })} placeholder="이메일" className="bg-[#0c0a09] px-8 py-4 rounded-2xl border border-stone-800 text-xs text-stone-200 font-bold outline-none focus:border-sky-500/30 transition shadow-inner" />
                </div>
                <label className="flex items-center justify-center w-full px-8 py-5 border-2 border-dashed border-stone-800 rounded-2xl cursor-pointer hover:border-sky-500/30 hover:bg-sky-500/5 transition-all group/upload">
                  <span className="text-[10px] font-black text-stone-600 group-hover/upload:text-sky-500 uppercase tracking-widest transition-colors">
                    {s.solutionFiles.length > 0 ? `📄 ${s.solutionFiles.length} 답안 로드 완료` : '학생 답안지 업로드 (이미지/PDF)'}
                  </span>
                  <input type="file" multiple onChange={(e) => onFormChange({ students: formData.students.map(item => item.id === s.id ? {...item, solutionFiles: Array.from(e.target.files || [])} : item) })} className="sr-only" />
                </label>
              </div>
            ))
          )}
        </div>
      </div>

      <button
        onClick={onGenerate}
        disabled={isLoading || formData.students.length === 0 || !formData.scoringCriteria}
        className="w-full py-8 bg-gradient-to-r from-sky-600 to-indigo-600 hover:from-sky-500 hover:to-indigo-500 text-white rounded-[3.5rem] font-black text-2xl shadow-3xl shadow-sky-900/30 transform transition active:scale-[0.98] disabled:opacity-20 disabled:grayscale flex items-center justify-center"
      >
        {isLoading ? (
          <div className="flex items-center">
            <LoadingSpinnerIcon className="animate-spin w-8 h-8 mr-6" />
            분석 엔진 가동 중...
          </div>
        ) : (
          <div className="flex items-center">
            <span className="mr-4 tracking-tighter uppercase">Batch Analysis Start</span>
            <span className="px-4 py-1.5 bg-white/20 rounded-2xl text-[11px] font-black">{formData.students.length}명</span>
          </div>
        )}
      </button>
    </div>
  );
};
